async fn cloud_mcp_signal_desktop_closing(app: &AppHandle, reason: &str) -> Result<Value, String> {
    let state = app.state::<CloudMcpState>().inner().clone();
    if !cloud_mcp_status_snapshot(&state).await.global_ws_connected {
        return Ok(json!({
            "ok": true,
            "sent": false,
            "reason": "websocket_not_connected",
        }));
    }

    let reason = reason.trim();
    let lifecycle_result = timeout(
        Duration::from_millis(900),
        cloud_mcp_send_lifecycle_event(
            &state,
            "desktop_client_closing",
            "closing",
            Some(if reason.is_empty() {
                "app_shutdown"
            } else {
                reason
            }),
        ),
    )
    .await;
    let _ = timeout(
        Duration::from_millis(900),
        cloud_mcp_send_app_ws_close_request(&state, reason),
    )
    .await;
    sleep(Duration::from_millis(250)).await;
    let result = lifecycle_result
        .map_err(|_| "Timed out sending desktop close signal to Cloud MCP.".to_string())??;
    Ok(result)
}

const CLOUD_MCP_LEGACY_SESSION_STATE_KEY: &str = "desktop-session";

fn cloud_mcp_remove_legacy_desktop_session(app: &AppHandle) {
    if let Ok(path) = app_local_state_path(app, CLOUD_MCP_LEGACY_SESSION_STATE_KEY) {
        let _ = fs::remove_file(&path);
        let _ = fs::remove_file(path.with_extension("json.tmp"));
    }
}

async fn cloud_mcp_apply_desktop_auth_session(
    app: AppHandle,
    state: &CloudMcpState,
    token: Option<String>,
    scope_type: Option<String>,
    team_id: Option<String>,
    plan_name: Option<String>,
    device_limit: Option<u64>,
) -> Result<CloudMcpStatus, String> {
    let token = token
        .unwrap_or_default()
        .replace(|character: char| character.is_control(), "")
        .trim()
        .to_string();
    let desktop_session_token = if token.is_empty() {
        None
    } else {
        validate_auth_value("Desktop session", &token)?;
        Some(token)
    };
    let (billing_scope_type, team_id) = cloud_mcp_account_scope_from_values(scope_type, team_id);
    let plan_name = cloud_mcp_plan_name_from_value(plan_name);
    let device_limit = cloud_mcp_device_limit_from_value(device_limit, &plan_name);
    let previous_auth = {
        let auth = state.auth.lock().await;
        (
            auth.desktop_session_token.clone(),
            auth.billing_scope_type.clone(),
            auth.team_id.clone(),
        )
    };
    let account_context_changed = previous_auth.0 != desktop_session_token
        || previous_auth.1 != billing_scope_type
        || previous_auth.2 != team_id;
    cloud_mcp_remove_legacy_desktop_session(&app);

    {
        let mut auth = state.auth.lock().await;
        auth.desktop_session_token = desktop_session_token.clone();
        auth.appwrite_jwt = None;
        auth.appwrite_jwt_expires_ms = None;
        auth.billing_scope_type = billing_scope_type.clone();
        auth.team_id = team_id.clone();
        auth.plan_name = plan_name.clone();
        auth.device_limit = device_limit;
    }
    cloud_mcp_update_process_auth_cache(
        desktop_session_token,
        None,
        None,
        Some(billing_scope_type),
        team_id,
        Some(plan_name),
        device_limit,
    );
    let registration_was_blocked = state
        .global_ws_registration_blocked
        .swap(false, Ordering::SeqCst);
    if account_context_changed {
        {
            let mut snapshots = state.runtime_snapshots.lock().await;
            *snapshots = CloudMcpRuntimeSnapshots::default();
        }
        {
            let mut runtime = state.inner.lock().await;
            runtime.account_device_live_state_snapshot = None;
            runtime.registered_workspaces.clear();
        }
        cloud_mcp_mark_global_ws_disconnected(
            state,
            "Cloud MCP account scope changed; reconnecting websocket with fresh scope.",
        )
        .await;
    }
    if registration_was_blocked {
        let mut runtime = state.inner.lock().await;
        if runtime.global_ws_status == "device_limit_reached" {
            runtime.connected = false;
            runtime.status = "starting".to_string();
            runtime.last_error.clear();
            runtime.global_ws_connected = false;
            runtime.global_ws_status = "starting".to_string();
            runtime.global_ws_last_error.clear();
            runtime.global_ws_connection_id = None;
            runtime.global_ws_message_token = None;
        }
        drop(runtime);
        state.global_ws_reconnect.notify_waiters();
    }

    Ok(cloud_mcp_status_snapshot(state).await)
}

#[tauri::command]
async fn cloud_mcp_get_status(state: State<'_, CloudMcpState>) -> Result<CloudMcpStatus, String> {
    Ok(cloud_mcp_status_snapshot(state.inner()).await)
}

#[tauri::command]
async fn cloud_mcp_get_network_diagnostics(
    state: State<'_, CloudMcpState>,
) -> Result<Value, String> {
    let now = cloud_mcp_now_ms();
    let status = cloud_mcp_status_snapshot(state.inner()).await;
    let status_value = serde_json::to_value(&status).unwrap_or_else(|_| json!({}));
    let sync_activity = status.sync_activity.clone();
    let activities = sync_activity
        .get("activities")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let recent_frames = cloud_mcp_network_recent_frame_values(CLOUD_MCP_NETWORK_RECENT_FRAME_MAX);
    let inbound_recent = recent_frames
        .iter()
        .filter(|frame| {
            let direction = frame
                .get("direction")
                .and_then(Value::as_str)
                .unwrap_or_default();
            matches!(direction, "down" | "both" | "control")
        })
        .cloned()
        .collect::<Vec<_>>();
    let outbound_recent = recent_frames
        .iter()
        .filter(|frame| {
            let direction = frame
                .get("direction")
                .and_then(Value::as_str)
                .unwrap_or_default();
            matches!(direction, "up" | "both" | "control")
        })
        .cloned()
        .collect::<Vec<_>>();
    let outbox_rows = cloud_mcp_outbox_diagnostic_rows(CLOUD_MCP_NETWORK_DIAGNOSTIC_OUTBOX_LIMIT);
    Ok(json!({
        "nowMs": now,
        "now_ms": now,
        "status": status_value,
        "connection": {
            "connected": status.connected,
            "status": status.status.clone(),
            "lastError": status.last_error.clone(),
            "last_error": status.last_error.clone(),
            "lastConnectedMs": status.last_connected_ms,
            "last_connected_ms": status.last_connected_ms,
            "globalWsConnected": status.global_ws_connected,
            "global_ws_connected": status.global_ws_connected,
            "globalWsStatus": status.global_ws_status.clone(),
            "global_ws_status": status.global_ws_status.clone(),
            "globalWsLastError": status.global_ws_last_error.clone(),
            "global_ws_last_error": status.global_ws_last_error.clone(),
            "globalWsLastConnectedMs": status.global_ws_last_connected_ms,
            "global_ws_last_connected_ms": status.global_ws_last_connected_ms,
            "contract": status.connection_contract.clone(),
        },
        "health": cloud_mcp_network_health_payload(now),
        "outbox": {
            "pendingCount": status.outbox_pending_count,
            "pending_count": status.outbox_pending_count,
            "retryingCount": status.outbox_retrying_count,
            "retrying_count": status.outbox_retrying_count,
            "deadLetterCount": status.outbox_dead_letter_count,
            "dead_letter_count": status.outbox_dead_letter_count,
            "oldestPendingMs": status.outbox_oldest_pending_ms,
            "oldest_pending_ms": status.outbox_oldest_pending_ms,
            "rows": outbox_rows,
        },
        "inbox": {
            "activityCount": activities.iter().filter(|activity| {
                let direction = activity
                    .get("direction")
                    .and_then(Value::as_str)
                    .unwrap_or_default();
                matches!(direction, "down" | "both" | "control")
            }).count(),
            "activity_count": activities.iter().filter(|activity| {
                let direction = activity
                    .get("direction")
                    .and_then(Value::as_str)
                    .unwrap_or_default();
                matches!(direction, "down" | "both" | "control")
            }).count(),
            "recent": inbound_recent,
        },
        "outbound": {
            "recent": outbound_recent,
        },
        "syncActivity": sync_activity.clone(),
        "sync_activity": sync_activity,
        "recentFrames": recent_frames.clone(),
        "recent_frames": recent_frames,
        "registeredWorkspaces": status.registered_workspaces.clone(),
        "registered_workspaces": status.registered_workspaces,
    }))
}

#[tauri::command]
async fn cloud_mcp_get_cached_workspace_todos(
    repo_path: Option<String>,
    workspace_id: Option<String>,
) -> Result<Value, String> {
    let safe_workspace_id = workspace_id
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string);
    let repo_id = repo_path
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(|path| {
            cloud_mcp_repo_request(path.to_string(), safe_workspace_id.clone(), None).repo_id
        });
    let scoped = cloud_mcp_todo_mirror_workspace_todos_from_store(
        repo_id.as_deref(),
        safe_workspace_id.as_deref(),
    );
    let fallback = if scoped.is_none() && repo_id.is_some() && safe_workspace_id.is_some() {
        cloud_mcp_todo_mirror_workspace_todos_from_store(None, safe_workspace_id.as_deref())
    } else {
        None
    };
    Ok(scoped.or(fallback).unwrap_or_else(|| json!({})))
}

async fn cloud_mcp_get_billing_status_for_state(state: &CloudMcpState) -> Result<Value, String> {
    let token = cloud_mcp_authorization_bearer(state)
        .await?
        .ok_or_else(|| "Cloud MCP auth token is not available.".to_string())?;
    let target = cloud_mcp_asset_http_target_async(state, "/v1/billing/status")
        .await
        .map_err(|error| format!("Cloud billing direct route unavailable: {error}"))?;
    let (billing_scope_type, team_id) = cloud_mcp_account_scope(state).await;

    let client = http_client(Duration::from_secs(DEFAULT_API_TIMEOUT_SECS))?;
    let response = client
        .post(&target.url)
        .headers(cloud_mcp_asset_http_headers(
            Some(token.as_str()),
            target.route_token.as_deref(),
        )?)
        .json(&json!({
            "scopeType": billing_scope_type,
            "teamId": team_id,
        }))
        .send()
        .await
        .map_err(|error| format!("Unable to load billing status: {error}"))?;

    let billing = read_api_response(response, "Unable to load billing status.").await?;
    let ledger = cloud_mcp_diffforge_credit_ledger_summary(100);
    Ok(cloud_mcp_merge_diffforge_credit_ledger(billing, ledger))
}

#[tauri::command]
async fn cloud_mcp_get_billing_status(state: State<'_, CloudMcpState>) -> Result<Value, String> {
    cloud_mcp_get_billing_status_for_state(state.inner()).await
}

#[tauri::command]
async fn cloud_mcp_register_workspace(
    state: State<'_, CloudMcpState>,
    repo_path: String,
    workspace_id: Option<String>,
    workspace_name: Option<String>,
) -> Result<CloudMcpWorkspaceRegistrationResult, String> {
    let prepared = tauri::async_runtime::spawn_blocking(move || {
        cloud_mcp_prepare_workspace_bundle(repo_path, workspace_id, workspace_name)
    })
    .await
    .map_err(|error| format!("Unable to prepare Cloud MCP registration: {error}"))??;

    cloud_mcp_register_prepared_workspace_bundle(state.inner(), prepared, "workspace_registration")
        .await
}

/// Workspace catalog mutations are Rust-owned and durable: the local scope
/// store commits synchronously and the cloud mutation rides the sync outbox,
/// so create/rename/delete survive offline stretches and background mode.
/// The response carries `queued: true` when the cloud has not confirmed yet.
#[tauri::command]
async fn cloud_mcp_workspace_catalog_upsert(
    app: AppHandle,
    state: State<'_, CloudMcpState>,
    workspace: Value,
    scope_key: Option<String>,
) -> Result<Value, String> {
    let mut workspace = workspace.as_object().cloned().unwrap_or_default();
    if !workspace.contains_key("origin_device_id") && !workspace.contains_key("originDeviceId") {
        let device_profile = cloud_mcp_desktop_device_profile();
        if let Some(device_id) = cloud_mcp_payload_text(&device_profile, &["device_id", "deviceId"])
        {
            workspace.insert("origin_device_id".to_string(), json!(device_id));
        }
    }
    let local_workspace = Value::Object(workspace.clone());
    let workspace_id =
        cloud_mcp_payload_text(&local_workspace, &["workspace_id", "workspaceId", "id"])
            .ok_or_else(|| "Workspace upsert requires a workspace id.".to_string())?;
    if let Some(scope_key) = scope_key
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
    {
        local_workspace_catalog_apply_upsert(&app, &scope_key, &local_workspace)?;
    }
    let cloud_workspace = json!({
        "workspace_id": workspace_id.clone(),
        "workspace_name": cloud_mcp_payload_text(&local_workspace, &["workspace_name", "workspaceName", "name"]),
        "workspace_active": local_workspace
            .get("workspace_active")
            .or_else(|| local_workspace.get("workspaceActive"))
            .or_else(|| local_workspace.get("active"))
            .cloned()
            .unwrap_or(Value::Null),
        "workspace_status": cloud_mcp_payload_text(&local_workspace, &["workspace_status", "workspaceStatus", "status", "state"]),
        "workspace_order": local_workspace
            .get("workspace_order")
            .or_else(|| local_workspace.get("workspaceOrder"))
            .or_else(|| local_workspace.get("workspace_index"))
            .or_else(|| local_workspace.get("workspaceIndex"))
            .or_else(|| local_workspace.get("order"))
            .cloned()
            .unwrap_or(Value::Null),
    });
    let scope_payload = cloud_mcp_process_account_scope_payload();
    let mut payload = json!({
        "workspace": cloud_workspace,
        "workspace_id": workspace_id,
    });
    if let Some(object) = payload.as_object_mut() {
        if let Some(scope_object) = scope_payload.as_object() {
            for (key, value) in scope_object {
                object.insert(key.clone(), value.clone());
            }
        }
    }
    {
        let device_profile = cloud_mcp_desktop_device_profile();
        let mut snapshots = state.inner().runtime_snapshots.lock().await;
        let mut workspace_items = snapshots
            .workspace_catalog
            .as_ref()
            .and_then(|snapshot| snapshot.get("workspaces"))
            .and_then(Value::as_array)
            .cloned()
            .unwrap_or_default();
        let upsert_index = workspace_items.iter().position(|item| {
            cloud_mcp_payload_text(item, &["workspace_id", "workspaceId", "id"]).as_deref()
                == Some(workspace_id.as_str())
        });
        match upsert_index {
            Some(index) => workspace_items[index] = payload["workspace"].clone(),
            None => workspace_items.push(payload["workspace"].clone()),
        }
        snapshots.workspace_catalog = Some(json!({
            "source": "rust-diffforge-workspace-catalog",
            "event_kind": "device_live_state_snapshot",
            "reason": "workspace_catalog_upsert",
            "client_id": CLOUD_MCP_RUST_CLIENT_ID,
            "device_id": device_profile["device_id"].clone(),
            "device_name": device_profile["device_name"].clone(),
            "machine_id": device_profile["device_id"].clone(),
            "machine_name": device_profile["machine_name"].clone(),
            "platform": device_profile["platform"].clone(),
            "form_factor": device_profile["form_factor"].clone(),
            "client_kind": device_profile["client_kind"].clone(),
            "snapshot_id": format!("device-workspace-catalog-{}-{}", cloud_mcp_now_ms(), uuid::Uuid::new_v4()),
            "snapshot_full": true,
            "authoritative": true,
            "workspaces": workspace_items,
            "summary": "Desktop workspace catalog synced.",
            "ts_ms": cloud_mcp_now_ms(),
        }));
    }
    cloud_mcp_publish_device_live_state_snapshot(state.inner(), "workspace_catalog_upsert").await;
    cloud_mcp_post_event_endpoint(state.inner(), "workspace_catalog_upsert", &payload).await
}

#[tauri::command]
async fn cloud_mcp_workspace_catalog_delete(
    app: AppHandle,
    state: State<'_, CloudMcpState>,
    workspace_id: String,
    reason: Option<String>,
    scope_key: Option<String>,
) -> Result<Value, String> {
    let workspace_id = workspace_id.trim().to_string();
    if workspace_id.is_empty() {
        return Err("Workspace delete requires a workspace id.".to_string());
    }
    // Pure local delete: the row leaves the store immediately and never comes
    // back (workspace ids are unique, the server keeps a deleted-ids ledger).
    if let Some(scope_key) = scope_key
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
    {
        let _ = local_workspace_catalog_apply_delete(&app, &scope_key, &workspace_id)?;
    }
    let scope_payload = cloud_mcp_process_account_scope_payload();
    let mut payload = json!({
        "workspace_id": workspace_id,
        "reason": reason
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| "workspace_deleted".to_string()),
    });
    if let Some(object) = payload.as_object_mut() {
        if let Some(scope_object) = scope_payload.as_object() {
            for (key, value) in scope_object {
                object.insert(key.clone(), value.clone());
            }
        }
    }
    let removed_catalog_snapshots = {
        let mut snapshots = state.inner().runtime_snapshots.lock().await;
        cloud_mcp_filter_deleted_workspace_snapshot(
            &mut snapshots.workspace_catalog,
            &workspace_id,
            "catalog",
        )
    };
    cloud_mcp_publish_device_live_state_snapshot(state.inner(), "workspace_catalog_delete").await;

    let mut response =
        cloud_mcp_post_event_endpoint(state.inner(), "workspace_catalog_delete", &payload).await?;
    if let Some(object) = response.as_object_mut() {
        object.insert(
            "removedCatalogSnapshots".to_string(),
            json!(removed_catalog_snapshots),
        );
    }
    Ok(response)
}

// Workspace ids with a catalog delete still queued in the outbox: stale cloud
// list responses and broadcasts must not show them while the delete drains.
fn cloud_mcp_outbox_pending_catalog_delete_ids() -> HashSet<String> {
    let mut ids = HashSet::new();
    let Ok(conn) = cloud_mcp_open_outbox_conn() else {
        return ids;
    };
    let Ok(mut statement) = conn.prepare(&format!(
        "SELECT payload_json
         FROM {CLOUD_MCP_OUTBOX_TABLE}
         WHERE event_kind='workspace_catalog_delete'
           AND status IN ('queued', 'retrying', 'in_flight')"
    )) else {
        return ids;
    };
    let Ok(rows) = statement.query_map([], |row| row.get::<_, String>(0)) else {
        return ids;
    };
    for payload_json in rows.flatten() {
        if let Ok(payload) = serde_json::from_str::<Value>(&payload_json) {
            if let Some(workspace_id) =
                cloud_mcp_payload_text(&payload, &["workspace_id", "workspaceId"])
            {
                ids.insert(workspace_id);
            }
        }
    }
    ids
}

fn cloud_mcp_filter_pending_catalog_deletes(mut data: Value) -> Value {
    let pending = cloud_mcp_outbox_pending_catalog_delete_ids();
    if pending.is_empty() {
        return data;
    }
    if let Some(workspaces) = data.get_mut("workspaces").and_then(Value::as_array_mut) {
        workspaces.retain(|workspace| {
            cloud_mcp_payload_text(workspace, &["workspace_id", "workspaceId", "id"])
                .map(|workspace_id| !pending.contains(&workspace_id))
                .unwrap_or(true)
        });
        let count = workspaces.len();
        if let Some(object) = data.as_object_mut() {
            object.insert("workspace_count".to_string(), json!(count));
            object.insert("workspaceCount".to_string(), json!(count));
        }
    }
    data
}

#[tauri::command]
async fn cloud_mcp_workspace_catalog_list(
    state: State<'_, CloudMcpState>,
    scope_type: Option<String>,
    team_id: Option<String>,
    scope_key: Option<String>,
) -> Result<Value, String> {
    let (active_scope_type, active_team_id) = cloud_mcp_account_scope(state.inner()).await;
    let active_scope_key =
        cloud_mcp_account_scope_key_from_parts(&active_scope_type, active_team_id.as_deref());
    let requested_scope = scope_key
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
        .unwrap_or_else(|| {
            let (requested_scope_type, requested_team_id) =
                cloud_mcp_account_scope_from_values(scope_type, team_id);
            cloud_mcp_account_scope_key_from_parts(
                &requested_scope_type,
                requested_team_id.as_deref(),
            )
        });
    if requested_scope != active_scope_key {
        return Err(format!(
            "Workspace catalog scope changed before cloud list completed ({requested_scope} != {active_scope_key})."
        ));
    }
    let payload =
        cloud_mcp_account_scope_payload_from_parts(&active_scope_type, active_team_id.as_deref());
    let response = cloud_mcp_ws_request(state.inner(), "workspace_catalog_list", &payload).await?;
    Ok(cloud_mcp_filter_pending_catalog_deletes(
        cloud_mcp_response_data(&response),
    ))
}

#[tauri::command]
async fn cloud_mcp_sync_workspace(
    state: State<'_, CloudMcpState>,
    repo_path: String,
    workspace_id: Option<String>,
    workspace_name: Option<String>,
) -> Result<CloudMcpWorkspaceRegistrationResult, String> {
    let prepared = tauri::async_runtime::spawn_blocking(move || {
        cloud_mcp_prepare_workspace_bundle(repo_path, workspace_id, workspace_name)
    })
    .await
    .map_err(|error| format!("Unable to prepare Cloud MCP sync: {error}"))??;

    cloud_mcp_register_prepared_workspace_bundle(state.inner(), prepared, "workspace_sync").await
}

#[tauri::command]
async fn cloud_mcp_sync_agent_installations(
    state: State<'_, CloudMcpState>,
    repo_path: String,
    workspace_id: Option<String>,
    workspace_name: Option<String>,
    agent_statuses: Value,
    reason: Option<String>,
) -> Result<Value, String> {
    cloud_mcp_sync_agent_installations_internal(
        state.inner(),
        repo_path,
        workspace_id,
        workspace_name,
        agent_statuses,
        reason,
    )
    .await
}

/// Internal agent-inventory push so the headless watcher and remote levers
/// can converge the cloud without a tauri command context.
pub(crate) async fn cloud_mcp_sync_agent_installations_internal(
    state: &CloudMcpState,
    _repo_path: String,
    workspace_id: Option<String>,
    workspace_name: Option<String>,
    agent_statuses: Value,
    reason: Option<String>,
) -> Result<Value, String> {
    let clean_option = |value: Option<String>| {
        value
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
    };
    let workspace_id = clean_option(workspace_id);
    let workspace_name = clean_option(workspace_name);
    let reason = clean_option(reason).unwrap_or_else(|| "agent_status_refresh".to_string());
    let snapshot_id = format!(
        "agent-installations-{}-{}",
        cloud_mcp_now_ms(),
        uuid::Uuid::new_v4()
    );
    let device_profile = cloud_mcp_desktop_device_profile();
    let agent_items = agent_statuses
        .as_array()
        .ok_or_else(|| "Agent installation sync requires an agentStatuses array.".to_string())?;
    let coding_agents = agent_items
        .iter()
        .take(64)
        .filter_map(cloud_mcp_sanitize_coding_agent_status)
        .collect::<Vec<_>>();
    let agent_count = coding_agents.len();
    let payload = json!({
        "source": "rust-diffforge-device-live-agent-inventory",
        "event_kind": "device_live_state_snapshot",
        "device_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "platform": device_profile["platform"].clone(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "workspace_id": workspace_id,
        "workspace_name": workspace_name,
        "agent_id": "rust-diffforge",
        "agent_label": "Diff Forge Desktop",
        "reason": reason,
        "snapshot_id": snapshot_id,
        "agent_count": agent_count,
        "coding_agents": coding_agents,
        "summary": "Desktop coding agent capabilities synced.",
        "ts_ms": cloud_mcp_now_ms(),
    });

    {
        let mut snapshots = state.runtime_snapshots.lock().await;
        snapshots.agent_installations = Some(payload.clone());
    }
    cloud_mcp_publish_device_live_state_snapshot(state, &reason).await;
    Ok(cloud_mcp_background_sync_ack(
        "device_live_state_snapshot",
        "device_live_state_snapshot",
        &reason,
        json!({
            "stored": {
                "stored_count": agent_count,
                "agent_count": agent_count,
            },
            "stored_count": agent_count,
            "agent_count": agent_count,
        }),
    ))
}

fn cloud_mcp_sanitize_coding_agent_status(agent: &Value) -> Option<Value> {
    let raw_id = cloud_mcp_payload_text(agent, &["id", "agent_id", "agentId"])?;
    let id = cloud_mcp_canonical_coding_agent_id(&raw_id)?;
    let label = cloud_mcp_payload_text(agent, &["label", "agent_label", "agentLabel"])
        .unwrap_or_else(|| cloud_mcp_coding_agent_label(&id).to_string())
        .trim()
        .chars()
        .take(80)
        .collect::<String>();
    let installed = cloud_mcp_payload_bool(agent, &["installed"], false);
    let authenticated = cloud_mcp_payload_bool(agent, &["authenticated"], false);
    let npm_available = cloud_mcp_payload_bool(
        agent,
        &["npmAvailable"],
        cloud_mcp_payload_bool(agent, &["npm_available"], false),
    );
    let npm_installed = cloud_mcp_payload_bool(
        agent,
        &["npmInstalled"],
        cloud_mcp_payload_bool(agent, &["npm_installed"], false),
    );
    let npm_package_version = cloud_mcp_payload_text(agent, &["npmPackageVersion"])
        .or_else(|| cloud_mcp_payload_text(agent, &["npm_package_version"]))
        .unwrap_or_default();
    let npm_latest_version = cloud_mcp_payload_text(agent, &["npmLatestVersion"])
        .or_else(|| cloud_mcp_payload_text(agent, &["npm_latest_version"]))
        .unwrap_or_default();
    let npm_update_available = cloud_mcp_payload_bool(
        agent,
        &["npmUpdateAvailable"],
        cloud_mcp_payload_bool(agent, &["npm_update_available"], false),
    );
    let update_available = cloud_mcp_payload_bool(
        agent,
        &["updateAvailable"],
        cloud_mcp_payload_bool(agent, &["update_available"], npm_update_available),
    );
    let update_known = cloud_mcp_payload_bool(
        agent,
        &["updateKnown"],
        cloud_mcp_payload_bool(agent, &["update_known"], false),
    );
    let up_to_date = cloud_mcp_payload_bool(
        agent,
        &["upToDate"],
        cloud_mcp_payload_bool(agent, &["up_to_date"], false),
    );
    let installing = cloud_mcp_payload_bool(agent, &["installing"], false);
    let updating = cloud_mcp_payload_bool(agent, &["updating"], false);
    let operation = cloud_mcp_payload_text(agent, &["operation"]).unwrap_or_default();
    let package_status = cloud_mcp_payload_text(agent, &["packageStatus"])
        .or_else(|| cloud_mcp_payload_text(agent, &["package_status"]))
        .unwrap_or_else(|| {
            if installing {
                "installing".to_string()
            } else if updating {
                "updating".to_string()
            } else if update_available {
                "update_available".to_string()
            } else if up_to_date {
                "up_to_date".to_string()
            } else if installed {
                "installed".to_string()
            } else {
                "missing".to_string()
            }
        });
    Some(json!({
        "id": id.clone(),
        "label": if label.is_empty() { cloud_mcp_coding_agent_label(&id) } else { label.as_str() },
        "installed": installed,
        "authenticated": authenticated,
        "version": cloud_mcp_payload_text(agent, &["version"]).unwrap_or_default(),
        "npm_available": npm_available,
        "npmAvailable": npm_available,
        "npm_installed": npm_installed,
        "npmInstalled": npm_installed,
        "npm_package_version": npm_package_version.clone(),
        "npmPackageVersion": npm_package_version,
        "npm_latest_version": npm_latest_version.clone(),
        "npmLatestVersion": npm_latest_version,
        "npm_update_available": npm_update_available,
        "npmUpdateAvailable": npm_update_available,
        "update_available": update_available,
        "updateAvailable": update_available,
        "update_known": update_known,
        "updateKnown": update_known,
        "up_to_date": up_to_date,
        "upToDate": up_to_date,
        "installing": installing,
        "updating": updating,
        "operation": operation,
        "package_status": package_status.clone(),
        "packageStatus": package_status,
    }))
}

fn cloud_mcp_canonical_coding_agent_id(value: &str) -> Option<String> {
    match value
        .trim()
        .to_ascii_lowercase()
        .replace([' ', '_'], "-")
        .as_str()
    {
        "codex" | "openai-codex" => Some("codex".to_string()),
        "claude" | "claude-code" | "claudecode" => Some("claude".to_string()),
        "opencode" | "open-code" | "opencode-ai" | "open-code-ai" => Some("opencode".to_string()),
        _ => None,
    }
}

fn cloud_mcp_coding_agent_label(agent_id: &str) -> &'static str {
    match agent_id {
        "codex" => "Codex",
        "claude" => "Claude Code",
        "opencode" => "OpenCode",
        _ => "Coding Agent",
    }
}

#[tauri::command]
async fn cloud_mcp_sync_device_live_terminals(
    state: State<'_, CloudMcpState>,
    workspaces: Value,
    reason: Option<String>,
) -> Result<Value, String> {
    let clean_option = |value: Option<String>| {
        value
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
    };
    let reason = clean_option(reason).unwrap_or_else(|| "device_live_state_snapshot".to_string());
    let workspace_items = workspaces
        .as_array()
        .ok_or_else(|| "Workspace terminals sync requires a workspaces array.".to_string())?;
    let mut normalized_workspaces = Vec::new();
    let device_profile = cloud_mcp_desktop_device_profile();

    for (workspace_index, workspace) in workspace_items.iter().take(64).enumerate() {
        let Some(workspace_id) =
            cloud_mcp_payload_text(workspace, &["workspace_id", "workspaceId", "id"])
                .filter(|value| !value.trim().is_empty())
        else {
            continue;
        };
        let workspace_name =
            cloud_mcp_payload_text(workspace, &["workspace_name", "workspaceName", "name"])
                .unwrap_or_else(|| workspace_id.clone());
        let workspace_active = workspace
            .get("workspace_active")
            .or_else(|| workspace.get("workspaceActive"))
            .or_else(|| workspace.get("active"))
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let workspace_status = cloud_mcp_payload_text(
            workspace,
            &["workspace_status", "workspaceStatus", "status"],
        )
        .unwrap_or_else(|| {
            if workspace_active {
                "active".to_string()
            } else {
                "deactivated".to_string()
            }
        });
        let terminal_items = cloud_mcp_workspace_terminal_items(workspace);
        let terminals = terminal_items
            .iter()
            .enumerate()
            .map(|(index, terminal)| {
                let terminal_index = terminal
                    .get("terminal_index")
                    .or_else(|| terminal.get("terminalIndex"))
                    .and_then(Value::as_i64)
                    .unwrap_or(index as i64)
                    .clamp(0, 255);
                let agent_kind = cloud_mcp_payload_text(
                    terminal,
                    &[
                        "agent_kind",
                        "agentKind",
                        "agent_id",
                        "agentId",
                        "role",
                        "provider",
                        "binary",
                        "kind",
                    ],
                )
                .unwrap_or_else(|| "terminal".to_string());
                let agent_label =
                    cloud_mcp_payload_text(terminal, &["agent_label", "agentLabel", "label"])
                        .unwrap_or_else(|| agent_kind.clone());
                let terminal_nickname = cloud_mcp_terminal_nickname_text(
                    terminal,
                    &[
                        "terminal_nickname",
                        "terminalNickname",
                        "terminal_name",
                        "terminalName",
                        "display_name",
                        "displayName",
                    ],
                );
                let status = cloud_mcp_payload_text(terminal, &["status", "state"])
                    .unwrap_or_else(|| "active".to_string());
                let native_rail_state = cloud_mcp_payload_text(
                    terminal,
                    &[
                        "native_rail_state",
                        "nativeRailState",
                        "rail_state",
                        "railState",
                        "top_rail_state",
                        "topRailState",
                    ],
                );
                let native_rail_label = cloud_mcp_payload_text(
                    terminal,
                    &[
                        "native_rail_label",
                        "nativeRailLabel",
                        "rail_label",
                        "railLabel",
                        "top_rail_label",
                        "topRailLabel",
                    ],
                );
                let activity_status = cloud_mcp_payload_text(
                    terminal,
                    &["activity_status", "activityStatus"],
                )
                .or_else(|| native_rail_state.clone())
                .unwrap_or_else(|| status.clone());
                let display_status = cloud_mcp_payload_text(
                    terminal,
                    &["display_status", "displayStatus"],
                )
                .or_else(|| native_rail_label.clone())
                .or_else(|| native_rail_state.clone())
                .unwrap_or_else(|| activity_status.clone());
                let terminal_status = cloud_mcp_payload_text(
                    terminal,
                    &["terminal_status", "terminalStatus", "reported_status", "reportedStatus"],
                )
                .unwrap_or_else(|| status.clone());
                let session_state =
                    cloud_mcp_payload_text(terminal, &["session_state", "sessionState"])
                        .unwrap_or_else(|| "unknown".to_string());
                let terminal_instance_id = terminal
                    .get("terminal_instance_id")
                    .or_else(|| terminal.get("terminalInstanceId"))
                    .cloned()
                    .unwrap_or(Value::Null);
                let status_seq = terminal
                    .get("status_seq")
                    .or_else(|| terminal.get("statusSeq"))
                    .cloned()
                    .unwrap_or(Value::Null);
                let input_ready = terminal
                    .get("input_ready")
                    .or_else(|| terminal.get("inputReady"))
                    .cloned()
                    .unwrap_or(Value::Null);
                let pane_id = cloud_mcp_payload_text(
                    terminal,
                    &[
                        "pane_id",
                        "paneId",
                        "target_terminal_id",
                        "targetTerminalId",
                    ],
                );
                let terminal_id = cloud_mcp_payload_text(
                    terminal,
                    &[
                        "terminal_id",
                        "terminalId",
                        "target_terminal_id",
                        "targetTerminalId",
                        "pane_id",
                        "paneId",
                    ],
                );
                json!({
                    "presence_agent_id": cloud_mcp_payload_text(
                        terminal,
                        &["presence_agent_id", "presenceAgentId", "id"],
                    ),
                    "agent_kind": agent_kind,
                    "agent_label": agent_label,
                    "activity_status": activity_status,
                    "display_name": terminal_nickname.clone(),
                    "display_status": display_status,
                    "status": status,
                    "session_state": session_state,
                    "terminal_name": terminal_nickname.clone(),
                    "terminal_nickname": terminal_nickname,
                    "terminal_index": terminal_index,
                    "terminal_epoch": cloud_mcp_payload_text(terminal, &["terminal_epoch", "terminalEpoch"]),
                    "terminal_instance_id": terminal_instance_id,
                    "terminal_lifecycle": cloud_mcp_payload_text(terminal, &["terminal_lifecycle", "terminalLifecycle", "lifecycle"]),
                    "native_rail_state": native_rail_state,
                    "native_rail_label": native_rail_label,
                    "readiness": cloud_mcp_payload_text(terminal, &["readiness", "terminal_readiness", "terminalReadiness"]),
                    "terminal_status": terminal_status,
                    "command_phase": cloud_mcp_payload_text(terminal, &["command_phase", "commandPhase"]),
                    "execution_phase": cloud_mcp_payload_text(terminal, &["execution_phase", "executionPhase"]),
                    "turn_id": cloud_mcp_payload_text(terminal, &["turn_id", "turnId", "latest_turn_id", "latestTurnId"]),
                    "turn_status": cloud_mcp_payload_text(terminal, &["turn_status", "turnStatus", "latest_turn_status", "latestTurnStatus"]),
                    "status_seq": status_seq,
                    "input_ready": input_ready,
                    "parked": terminal
                        .get("parked")
                        .or_else(|| terminal.get("terminal_parked"))
                        .or_else(|| terminal.get("terminalParked"))
                        .cloned()
                        .unwrap_or(Value::Null),
                    "parked_prompt_title": cloud_mcp_payload_text(
                        terminal,
                        &[
                            "parked_prompt_title",
                            "parkedPromptTitle",
                            "parked_title",
                            "parkedTitle",
                        ],
                    ),
                    "pane_id": pane_id,
                    "terminal_id": terminal_id.clone(),
                    "target_terminal_id": terminal_id,
                    "thread_id": cloud_mcp_payload_text(terminal, &["thread_id", "threadId"]),
                    "color": cloud_mcp_payload_text(terminal, &["color", "accent", "accentColor"]),
                    "color_slot": cloud_mcp_payload_text(terminal, &["color_slot", "colorSlot", "color_index", "colorIndex", "slot"]),
                    "last_known_runtime": terminal
                        .get("last_known_runtime")
                        .or_else(|| terminal.get("lastKnownRuntime"))
                        .cloned()
                        .unwrap_or(Value::Null),
                    "runtime_read_only": terminal
                        .get("runtime_read_only")
                        .or_else(|| terminal.get("runtimeReadOnly"))
                        .cloned()
                        .unwrap_or(Value::Null),
                    "commandable": terminal
                        .get("commandable")
                        .cloned()
                        .unwrap_or(Value::Null),
                    "connected": terminal
                        .get("connected")
                        .cloned()
                        .unwrap_or(Value::Null),
                    "native_connected": terminal
                        .get("native_connected")
                        .or_else(|| terminal.get("nativeConnected"))
                        .cloned()
                        .unwrap_or(Value::Null),
                    "waiting_on": terminal
                        .get("waiting_on")
                        .or_else(|| terminal.get("waitingOn"))
                        .cloned()
                        .unwrap_or(Value::Null),
                })
            })
            .collect::<Vec<_>>();

        let (workspace_runtime_seq, workspace_runtime_epoch) =
            cloud_mcp_workspace_runtime_ordering(state.inner(), workspace);
        let workspace_order = cloud_mcp_payload_u64(
            workspace,
            &[
                "workspace_order",
                "workspaceOrder",
                "workspace_index",
                "workspaceIndex",
                "sort_order",
                "sortOrder",
                "order",
            ],
        )
        .unwrap_or(workspace_index as u64);
        let terminal_clear_reason =
            cloud_mcp_payload_text(workspace, &["terminal_clear_reason", "terminalClearReason"])
                .unwrap_or_default();
        let terminal_list_empty_authoritative = workspace
            .get("terminal_list_empty_authoritative")
            .or_else(|| workspace.get("terminalListEmptyAuthoritative"))
            .and_then(Value::as_bool)
            .unwrap_or(false)
            && terminal_clear_reason == "all_terminals_closed";
        let terminal_list_authoritative = workspace
            .get("terminal_list_authoritative")
            .or_else(|| workspace.get("terminalListAuthoritative"))
            .and_then(Value::as_bool)
            .unwrap_or(false)
            || terminal_list_empty_authoritative;
        let workspace_value = json!({
            "device_id": device_profile["device_id"].clone(),
            "workspace_active": workspace_active,
            "workspace_id": workspace_id,
            "workspace_name": workspace_name,
            "workspace_status": workspace_status,
            "workspace_runtime_seq": workspace_runtime_seq,
            "workspace_runtime_epoch": workspace_runtime_epoch,
            "workspace_order": workspace_order,
            "terminal_clear_reason": terminal_clear_reason,
            "terminal_list_empty_authoritative": terminal_list_empty_authoritative,
            "terminal_list_authoritative": terminal_list_authoritative,
            "last_known_runtime": workspace
                .get("last_known_runtime")
                .or_else(|| workspace.get("lastKnownRuntime"))
                .cloned()
                .unwrap_or(Value::Null),
            "runtime_read_only": workspace
                .get("runtime_read_only")
                .or_else(|| workspace.get("runtimeReadOnly"))
                .cloned()
                .unwrap_or(Value::Null),
            "commandable": workspace
                .get("commandable")
                .cloned()
                .unwrap_or(Value::Null),
            "terminals": terminals,
        });
        normalized_workspaces.push(workspace_value);
    }
    let terminal_count = normalized_workspaces
        .iter()
        .map(|workspace| {
            workspace
                .get("terminals")
                .and_then(Value::as_array)
                .map(Vec::len)
                .unwrap_or_default()
        })
        .sum::<usize>();
    let workspace_count = normalized_workspaces.len();

    let reason_for_ack = reason.clone();
    let payload = json!({
        "source": "rust-diffforge-device-live-terminals",
        "event_kind": "device_live_state_snapshot",
        "device_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "platform": device_profile["platform"].clone(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "agent_id": "rust-diffforge",
        "agent_label": "Diff Forge Desktop",
        "reason": reason,
        "workspace_count": workspace_count,
        "terminal_count": terminal_count,
        "workspaces": normalized_workspaces,
        "summary": "Desktop terminal state synced into the unified device live state.",
        "ts_ms": cloud_mcp_now_ms(),
    });

    {
        let mut snapshots = state.inner().runtime_snapshots.lock().await;
        snapshots.workspace_terminals = Some(payload.clone());
    }
    cloud_mcp_publish_device_live_state_snapshot(state.inner(), &reason_for_ack).await;

    let sync_key = "device_live_state_snapshot".to_string();
    Ok(cloud_mcp_background_sync_ack(
        "device_live_state_snapshot",
        &sync_key,
        &reason_for_ack,
        json!({
            "sent": true,
            "stored": {
                "stored_count": terminal_count,
                "terminal_count": terminal_count,
                "workspace_count": workspace_count,
            },
            "stored_count": terminal_count,
            "terminal_count": terminal_count,
            "workspace_count": workspace_count,
        }),
    ))
}

fn cloud_mcp_lifecycle_status_key(value: &str) -> String {
    value.trim().to_ascii_lowercase().replace([' ', '-'], "_")
}

fn cloud_mcp_terminal_lifecycle_state(
    event_type: &str,
    status: &str,
    activity_status: &str,
    readiness: &str,
    execution_phase: &str,
    turn_status: &str,
) -> &'static str {
    let event_type = cloud_mcp_lifecycle_status_key(event_type);
    let status = cloud_mcp_lifecycle_status_key(status);
    let activity_status = cloud_mcp_lifecycle_status_key(activity_status);
    let readiness = cloud_mcp_lifecycle_status_key(readiness);
    let execution_phase = cloud_mcp_lifecycle_status_key(execution_phase);
    let turn_status = cloud_mcp_lifecycle_status_key(turn_status);
    let values = [
        event_type.as_str(),
        status.as_str(),
        activity_status.as_str(),
        readiness.as_str(),
        execution_phase.as_str(),
        turn_status.as_str(),
    ];

    if values
        .iter()
        .any(|value| matches!(*value, "closed" | "closing" | "exited" | "offline"))
    {
        return "closed";
    }
    if values
        .iter()
        .any(|value| matches!(*value, "error" | "failed" | "failure"))
    {
        return "error";
    }
    if values.iter().any(|value| {
        matches!(
            *value,
            "paused"
                | "parked"
                | "needs_input"
                | "awaiting_input"
                | "awaiting_user"
                | "provider_user_prompt_started"
                | "resume_ready"
        )
    }) {
        return "paused";
    }
    if values.iter().any(|value| {
        matches!(
            *value,
            "complete"
                | "completed"
                | "done"
                | "idle"
                | "input_ready"
                | "interrupted"
                | "interrupt"
                | "cancelled"
                | "canceled"
                | "ready"
                | "provider_turn_completed"
                | "provider_turn_interrupted"
        )
    }) {
        return "idle";
    }

    "thinking"
}

fn cloud_mcp_terminal_lifecycle_turn_status(
    event_type: &str,
    turn_status: &str,
    state: &str,
) -> &'static str {
    let event_type = cloud_mcp_lifecycle_status_key(event_type);
    let turn_status = cloud_mcp_lifecycle_status_key(turn_status);
    match turn_status.as_str() {
        "complete" | "completed" | "done" => "completed",
        "cancelled" | "canceled" => "cancelled",
        "interrupted" | "interrupt" => "interrupted",
        "failed" | "error" => "failed",
        "queued" | "submitted" | "pending" => "queued",
        "running" | "thinking" | "working" | "reasoning" => "running",
        _ => match event_type.as_str() {
            "provider_turn_completed" => "completed",
            "provider_turn_error" => "failed",
            "provider_turn_interrupted" => "interrupted",
            "remote_control_close" | "closed" | "exited" => "interrupted",
            _ => match state {
                "idle" => "completed",
                "error" => "failed",
                "closed" => "interrupted",
                _ => "running",
            },
        },
    }
}

fn cloud_mcp_terminal_lifecycle_readiness(state: &str, input_ready: Option<bool>) -> &'static str {
    if input_ready.unwrap_or(false) {
        return "ready";
    }
    match state {
        "idle" => "ready",
        "closed" => "closed",
        "error" => "error",
        "paused" => "needs_input",
        _ => "busy",
    }
}

fn cloud_mcp_next_terminal_lifecycle_seq(state: &CloudMcpState, candidate: Option<u64>) -> u64 {
    let now = cloud_mcp_now_ms();
    let candidate = candidate.unwrap_or(0).max(now);
    let mut previous = state.terminal_lifecycle_seq.load(Ordering::SeqCst);
    loop {
        let next = previous.saturating_add(1).max(candidate);
        match state.terminal_lifecycle_seq.compare_exchange(
            previous,
            next,
            Ordering::SeqCst,
            Ordering::SeqCst,
        ) {
            Ok(_) => return next,
            Err(current) => previous = current,
        }
    }
}

fn cloud_mcp_next_workspace_runtime_seq(state: &CloudMcpState, candidate: Option<u64>) -> u64 {
    let now = cloud_mcp_now_ms();
    let candidate = candidate.unwrap_or(0).max(now);
    let mut previous = state.workspace_runtime_seq.load(Ordering::SeqCst);
    loop {
        let next = previous.saturating_add(1).max(candidate);
        match state.workspace_runtime_seq.compare_exchange(
            previous,
            next,
            Ordering::SeqCst,
            Ordering::SeqCst,
        ) {
            Ok(_) => return next,
            Err(current) => previous = current,
        }
    }
}

fn cloud_mcp_workspace_runtime_epoch(state: &CloudMcpState) -> String {
    let epoch = state.global_ws_epoch.load(Ordering::SeqCst).max(1);
    format!("workspace-runtime-{epoch}")
}

fn cloud_mcp_workspace_runtime_ordering(state: &CloudMcpState, workspace: &Value) -> (u64, String) {
    let seq = cloud_mcp_next_workspace_runtime_seq(
        state,
        cloud_mcp_payload_u64(
            workspace,
            &[
                "workspace_runtime_seq",
                "workspaceRuntimeSeq",
                "runtime_seq",
                "runtimeSeq",
            ],
        ),
    );
    let epoch = cloud_mcp_payload_text(
        workspace,
        &[
            "workspace_runtime_epoch",
            "workspaceRuntimeEpoch",
            "runtime_epoch",
            "runtimeEpoch",
        ],
    )
    .unwrap_or_else(|| cloud_mcp_workspace_runtime_epoch(state));
    (seq, epoch)
}

fn cloud_mcp_copy_workspace_runtime_ordering(target: &mut Value, source: &Value) {
    let seq = source
        .get("workspace_runtime_seq")
        .or_else(|| source.get("workspaceRuntimeSeq"))
        .or_else(|| source.get("runtime_seq"))
        .or_else(|| source.get("runtimeSeq"))
        .cloned()
        .unwrap_or(Value::Null);
    let epoch = source
        .get("workspace_runtime_epoch")
        .or_else(|| source.get("workspaceRuntimeEpoch"))
        .or_else(|| source.get("runtime_epoch"))
        .or_else(|| source.get("runtimeEpoch"))
        .cloned()
        .unwrap_or(Value::Null);
    let order = source
        .get("workspace_order")
        .or_else(|| source.get("workspaceOrder"))
        .or_else(|| source.get("workspace_index"))
        .or_else(|| source.get("workspaceIndex"))
        .or_else(|| source.get("sort_order"))
        .or_else(|| source.get("sortOrder"))
        .or_else(|| source.get("order"))
        .cloned()
        .unwrap_or(Value::Null);
    let Some(object) = target.as_object_mut() else {
        return;
    };
    object.insert("workspace_runtime_seq".to_string(), seq.clone());
    object.insert("workspaceRuntimeSeq".to_string(), seq);
    object.insert("workspace_runtime_epoch".to_string(), epoch.clone());
    object.insert("workspaceRuntimeEpoch".to_string(), epoch);
    object.insert("workspace_order".to_string(), order.clone());
    object.insert("workspaceOrder".to_string(), order.clone());
    object.insert("workspace_index".to_string(), order.clone());
    object.insert("workspaceIndex".to_string(), order);
}

async fn cloud_mcp_apply_terminal_state_to_device_live_snapshot(
    state: &CloudMcpState,
    payload: &Value,
    reason: &str,
) {
    let workspace_id = cloud_mcp_payload_text(&payload, &["workspace_id", "workspaceId"])
        .unwrap_or_else(|| "workspace".to_string());
    let repo_id = cloud_mcp_payload_text(payload, &["repo_id", "repoId"]);
    let workspace_root = cloud_mcp_payload_text(payload, &["workspace_root", "workspaceRoot"]);
    let workspace_name = cloud_mcp_payload_text(payload, &["workspace_name", "workspaceName"]);
    let terminal_id = cloud_mcp_payload_text(
        payload,
        &[
            "terminal_id",
            "terminalId",
            "pane_id",
            "paneId",
            "target_terminal_id",
            "targetTerminalId",
        ],
    )
    .unwrap_or_else(|| "terminal".to_string());
    let terminal_instance_id = cloud_mcp_payload_u64(
        payload,
        &[
            "terminal_instance_id",
            "terminalInstanceId",
            "instance_id",
            "instanceId",
        ],
    )
    .unwrap_or_default();
    let observed_at_ms = cloud_mcp_payload_u64(payload, &["observed_at_ms", "observedAtMs"])
        .unwrap_or_else(cloud_mcp_now_ms);
    let device_profile = cloud_mcp_desktop_device_profile();

    let mut snapshots = state.runtime_snapshots.lock().await;
    if snapshots.workspace_terminals.is_none() {
        snapshots.workspace_terminals = Some(json!({
            "source": "rust-diffforge-device-live-terminals",
            "event_kind": "device_live_state_snapshot",
            "device": device_profile.clone(),
            "device_id": device_profile["device_id"].clone(),
            "device_name": device_profile["device_name"].clone(),
            "machine_id": device_profile["device_id"].clone(),
            "machine_name": device_profile["machine_name"].clone(),
            "platform": device_profile["platform"].clone(),
            "form_factor": device_profile["form_factor"].clone(),
            "client_kind": device_profile["client_kind"].clone(),
            "agent_id": "rust-diffforge",
            "agent_label": "Diff Forge Desktop",
            "reason": reason,
            "workspace_count": 0,
            "terminal_count": 0,
            "workspaces": [],
            "summary": "Desktop workspace terminals synced.",
            "ts_ms": observed_at_ms,
        }));
    }
    let Some(snapshot) = snapshots.workspace_terminals.as_mut() else {
        return;
    };
    if !snapshot
        .get("workspaces")
        .and_then(Value::as_array)
        .is_some()
    {
        if let Some(object) = snapshot.as_object_mut() {
            object.insert("workspaces".to_string(), json!([]));
        }
    }
    let (workspace_count, total_terminal_count) = {
        let Some(workspaces) = snapshot.get_mut("workspaces").and_then(Value::as_array_mut) else {
            return;
        };
        let workspace_index = workspaces.iter().position(|workspace| {
            cloud_mcp_payload_text(workspace, &["workspace_id", "workspaceId", "id"])
                .is_some_and(|value| value == workspace_id)
                || workspace_root.as_ref().is_some_and(|root| {
                    cloud_mcp_payload_text(workspace, &["workspace_root", "workspaceRoot"])
                        .is_some_and(|value| value == *root)
                })
        });
        let workspace_index = match workspace_index {
            Some(index) => index,
            None => {
                workspaces.push(json!({
                    "repo_id": repo_id,
                    "workspace_id": workspace_id,
                    "workspace_name": workspace_name,
                    "workspace_root": workspace_root,
                    "workspace_active": true,
                    "workspace_status": "active",
                    "terminal_count": 0,
                    "active_count": 0,
                    "terminals": [],
                }));
                workspaces.len().saturating_sub(1)
            }
        };
        let Some(workspace) = workspaces.get_mut(workspace_index) else {
            return;
        };
        if let Some(object) = workspace.as_object_mut() {
            object.insert("workspace_active".to_string(), json!(true));
            object.insert("workspace_status".to_string(), json!("active"));
            object.insert("reason".to_string(), json!(reason));
            object.insert("ts_ms".to_string(), json!(observed_at_ms));
            object
                .entry("terminals".to_string())
                .or_insert_with(|| json!([]));
        }
        if !workspace
            .get("terminals")
            .and_then(Value::as_array)
            .is_some()
        {
            if let Some(object) = workspace.as_object_mut() {
                object.insert("terminals".to_string(), json!([]));
            }
        }
        let Some(terminals) = workspace.get_mut("terminals").and_then(Value::as_array_mut) else {
            return;
        };
        let mut terminal_value = payload.clone();
        if let Some(object) = terminal_value.as_object_mut() {
            object.insert("terminal_id".to_string(), json!(terminal_id.clone()));
            object.insert("terminalId".to_string(), json!(terminal_id.clone()));
            object.insert(
                "terminal_instance_id".to_string(),
                json!(terminal_instance_id),
            );
            object.insert(
                "terminalInstanceId".to_string(),
                json!(terminal_instance_id),
            );
            object.insert("observed_at_ms".to_string(), json!(observed_at_ms));
            object.insert("observedAtMs".to_string(), json!(observed_at_ms));
        }
        let workspace_runtime_shutdown =
            cloud_mcp_terminal_state_is_workspace_runtime_shutdown(&terminal_value);
        if workspace_runtime_shutdown {
            cloud_mcp_mark_terminal_last_known_read_only(&mut terminal_value);
        }
        let terminal_removes_from_snapshot = !workspace_runtime_shutdown
            && cloud_mcp_terminal_state_removes_from_live_snapshot(&terminal_value);
        let existing_index = terminals.iter().position(|terminal| {
            cloud_mcp_presence_terminal_matches_instance(
                terminal,
                &terminal_id,
                terminal_instance_id,
            )
        });
        if terminal_removes_from_snapshot {
            terminals.retain(|terminal| {
                !cloud_mcp_presence_terminal_matches_instance(
                    terminal,
                    &terminal_id,
                    terminal_instance_id,
                )
            });
        } else if let Some(existing_index) = existing_index {
            if let Some(existing) = terminals.get_mut(existing_index) {
                cloud_mcp_live_state_merge_object(existing, terminal_value);
            }
        } else {
            terminals.push(terminal_value);
        }
        let terminal_count = terminals.len();
        let active_count = terminals
            .iter()
            .filter(|terminal| {
                let status = cloud_mcp_payload_text(
                    terminal,
                    &[
                        "status",
                        "state",
                        "activity_status",
                        "activityStatus",
                        "terminal_lifecycle",
                        "terminalLifecycle",
                    ],
                )
                .unwrap_or_default()
                .trim()
                .to_ascii_lowercase();
                !matches!(status.as_str(), "closed" | "deleted" | "removed")
            })
            .count();
        if let Some(object) = workspace.as_object_mut() {
            object.insert("terminal_count".to_string(), json!(terminal_count));
            object.insert("terminalCount".to_string(), json!(terminal_count));
            object.insert("active_count".to_string(), json!(active_count));
            object.insert("activeCount".to_string(), json!(active_count));
            object.insert("workspace_active".to_string(), json!(active_count > 0));
        }
        let total_terminal_count = workspaces
            .iter()
            .filter_map(|workspace| workspace.get("terminals").and_then(Value::as_array))
            .map(Vec::len)
            .sum::<usize>();
        (workspaces.len(), total_terminal_count)
    };
    if let Some(object) = snapshot.as_object_mut() {
        object.insert("reason".to_string(), json!(reason));
        object.insert("workspace_count".to_string(), json!(workspace_count));
        object.insert("terminal_count".to_string(), json!(total_terminal_count));
        object.insert("ts_ms".to_string(), json!(observed_at_ms));
    }
}

async fn cloud_mcp_publish_terminal_state_live_update(
    state: &CloudMcpState,
    payload: &Value,
    reason: &str,
) {
    cloud_mcp_apply_terminal_state_to_device_live_snapshot(state, payload, reason).await;
    cloud_mcp_publish_device_live_state_snapshot(state, reason).await;
}

pub(crate) async fn cloud_mcp_sync_terminal_activity_hook_delta(
    state: &CloudMcpState,
    payload: &TerminalActivityHookPayload,
) {
    let terminal_id = payload.pane_id.as_str();
    let terminal_key = cloud_mcp_terminal_key(terminal_id, payload.instance_id);
    let context_entry = {
        let runtime = state.inner.lock().await;
        runtime.terminal_contexts.get(&terminal_key).cloned()
    };
    let repo_id = context_entry
        .as_ref()
        .map(|entry| entry.repo_id.clone())
        .filter(|value| !value.trim().is_empty());
    let workspace_root = context_entry
        .as_ref()
        .map(|entry| workspace_path_display(&entry.repo_root))
        .or_else(|| payload.cwd.clone())
        .unwrap_or_default();
    let direct_prompt_refs = context_entry.as_ref().and_then(|entry| {
        Some(CloudMcpDirectPromptTodoRefs {
            todo_id: entry.todo_id.clone()?,
            dispatch_id: entry.todo_dispatch_id.clone()?,
            command_id: entry.todo_command_id.clone()?,
        })
    });
    let prompt_event_id = context_entry
        .as_ref()
        .and_then(|entry| entry.prompt_event_id.as_deref());
    let state_value = cloud_mcp_terminal_lifecycle_state(
        &payload.event_type,
        &payload.status,
        &payload.activity_status,
        "",
        &payload.command_phase,
        "",
    );
    let turn_status =
        cloud_mcp_terminal_lifecycle_turn_status(&payload.event_type, "", state_value);
    let readiness = cloud_mcp_terminal_lifecycle_readiness(state_value, Some(payload.input_ready));
    let status_seq = cloud_mcp_next_terminal_lifecycle_seq(state, Some(payload.observed_at_ms));
    let workspace_runtime_seq =
        cloud_mcp_next_workspace_runtime_seq(state, Some(payload.observed_at_ms));
    let workspace_runtime_epoch = cloud_mcp_workspace_runtime_epoch(state);
    let reason = payload.source.as_str();
    let delta = json!({
        "source": "rust-diffforge-activity-hook",
        "event_kind": "terminal_state_update",
        "v": 1,
        "repo_id": repo_id,
        "workspace_root": workspace_root,
        "workspace_id": payload.workspace_id,
        "workspace_name": payload.workspace_name,
        "workspace_runtime_seq": workspace_runtime_seq,
        "workspaceRuntimeSeq": workspace_runtime_seq,
        "workspace_runtime_epoch": workspace_runtime_epoch,
        "workspaceRuntimeEpoch": workspace_runtime_epoch,
        "terminal_id": terminal_id,
        "pane_id": terminal_id,
        "terminal_instance_id": payload.instance_id,
        "terminal_index": payload.terminal_index,
        "terminal_epoch": format!("{}:{}", terminal_id, payload.instance_id),
        "agent_kind": payload.agent_kind,
        "agent_type": payload.agent_type.as_str(),
        "agentType": payload.agent_type.as_str(),
        "agent_display_name": payload.agent_display_name.as_str(),
        "agentDisplayName": payload.agent_display_name.as_str(),
        "provider": payload.provider,
        "event_type": payload.event_type,
        "hook_event_name": payload.hook_event_name,
        "state": state_value,
        "status": state_value,
        "activity_status": state_value,
        "readiness": readiness,
        "turn_status": turn_status,
        "command_phase": payload.command_phase,
        "input_ready": payload.input_ready,
        "status_seq": status_seq,
        "observed_at_ms": payload.observed_at_ms,
        "hook_timestamp_ms": payload.hook_timestamp_ms,
        "turn_id": payload.turn_id,
        "provider_turn_id": payload.provider_turn_id,
        "provider_session_id": payload.provider_session_id,
        "prompt_event_id": prompt_event_id,
        "promptEventId": prompt_event_id,
        "todo_id": direct_prompt_refs.as_ref().map(|refs| refs.todo_id.as_str()),
        "todoId": direct_prompt_refs.as_ref().map(|refs| refs.todo_id.as_str()),
        "todo_dispatch_id": direct_prompt_refs.as_ref().map(|refs| refs.dispatch_id.as_str()),
        "todoDispatchId": direct_prompt_refs.as_ref().map(|refs| refs.dispatch_id.as_str()),
        "command_id": direct_prompt_refs.as_ref().map(|refs| refs.command_id.as_str()),
        "commandId": direct_prompt_refs.as_ref().map(|refs| refs.command_id.as_str()),
        "thread_id": payload.thread_id,
        "reason": reason,
        "summary": format!("Terminal {}.", state_value),
        "ts_ms": cloud_mcp_now_ms(),
    });
    let agent_session_observed = {
        let base_url = {
            let runtime = state.inner.lock().await;
            runtime.base_url.clone()
        };
        cloud_mcp_agent_session_upsert_lifecycle_delta(&base_url, &delta)
    };
    cloud_mcp_publish_terminal_state_live_update(state, &delta, reason).await;
    if let Some(agent_session_payload) = agent_session_observed {
        let priority = if matches!(state_value, "idle" | "paused" | "error" | "closed") {
            CLOUD_MCP_BACKGROUND_SYNC_PRIORITY_HIGH
        } else {
            CLOUD_MCP_BACKGROUND_SYNC_PRIORITY_MEDIUM
        };
        cloud_mcp_enqueue_agent_session_observed(state, agent_session_payload, reason, priority)
            .await;
    }
    if let (Some(refs), Some(status)) = (
        direct_prompt_refs.as_ref(),
        cloud_mcp_direct_prompt_dispatch_status_for_turn(turn_status),
    ) {
        cloud_mcp_record_direct_prompt_todo_dispatch_status(
            state,
            refs,
            &payload.workspace_id,
            status,
            json!({
                "reason": reason,
                "event_type": payload.event_type,
                "hook_event_name": payload.hook_event_name,
                "turn_status": turn_status,
                "state": state_value,
                "pane_id": terminal_id,
                "terminal_instance_id": payload.instance_id,
                "provider_session_id": payload.provider_session_id,
                "prompt_event_id": prompt_event_id,
            }),
        )
        .await;
    }
}

#[tauri::command]
async fn cloud_mcp_sync_terminal_status_event(
    state: State<'_, CloudMcpState>,
    workspace: Value,
    terminal: Value,
    reason: Option<String>,
) -> Result<Value, String> {
    let clean_option = |value: Option<String>| {
        value
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
    };
    let reason = clean_option(reason).unwrap_or_else(|| "terminal_state_update".to_string());
    let device_profile = cloud_mcp_desktop_device_profile();
    let repo_path = cloud_mcp_payload_text(
        &workspace,
        &[
            "repo_path",
            "repoPath",
            "workspace_root",
            "workspaceRoot",
            "workspace_root_directory",
            "workspaceRootDirectory",
            "workingDirectory",
            "rootDirectory",
            "terminalWorkspaceWorkingDirectory",
        ],
    )
    .or_else(|| {
        cloud_mcp_payload_text(
            &terminal,
            &[
                "repo_path",
                "repoPath",
                "workspace_root",
                "workspaceRoot",
                "workingDirectory",
                "rootDirectory",
            ],
        )
    })
    .unwrap_or_default();
    if repo_path.trim().is_empty() {
        return Err("Terminal status events require a workspace root.".to_string());
    }

    let workspace_id = cloud_mcp_payload_text(&workspace, &["workspace_id", "workspaceId", "id"])
        .or_else(|| cloud_mcp_payload_text(&terminal, &["workspace_id", "workspaceId"]));
    let workspace_name = cloud_mcp_payload_text(
        &workspace,
        &["workspace_name", "workspaceName", "name", "label"],
    );
    let workspace_active = workspace
        .get("workspace_active")
        .or_else(|| workspace.get("workspaceActive"))
        .or_else(|| workspace.get("active"))
        .and_then(Value::as_bool)
        .unwrap_or(true);
    let workspace_status = cloud_mcp_payload_text(
        &workspace,
        &["workspace_status", "workspaceStatus", "status"],
    )
    .unwrap_or_else(|| {
        if workspace_active {
            "active".to_string()
        } else {
            "deactivated".to_string()
        }
    });
    let req = cloud_mcp_repo_request(repo_path, workspace_id, workspace_name);

    let terminal_index = terminal
        .get("terminal_index")
        .or_else(|| terminal.get("terminalIndex"))
        .and_then(Value::as_i64)
        .unwrap_or(0)
        .clamp(0, 255);
    let agent_kind = cloud_mcp_payload_text(
        &terminal,
        &[
            "agent_kind",
            "agentKind",
            "agent_id",
            "agentId",
            "role",
            "provider",
            "binary",
            "kind",
        ],
    )
    .unwrap_or_else(|| "terminal".to_string());
    let status = cloud_mcp_payload_text(
        &terminal,
        &["status_after", "statusAfter", "status", "state"],
    )
    .unwrap_or_else(|| "idle".to_string());
    let activity_status = cloud_mcp_payload_text(
        &terminal,
        &[
            "activity_status",
            "activityStatus",
            "display_status",
            "displayStatus",
            "native_rail_state",
            "nativeRailState",
        ],
    )
    .unwrap_or_else(|| status.clone());
    let readiness = cloud_mcp_payload_text(
        &terminal,
        &[
            "readiness_after",
            "readinessAfter",
            "readiness",
            "terminal_readiness",
            "terminalReadiness",
        ],
    );
    let event_type = cloud_mcp_payload_text(
        &terminal,
        &[
            "event_type",
            "eventType",
            "type",
            "terminal_event_type",
            "terminalEventType",
        ],
    )
    .unwrap_or_else(|| "terminal.status".to_string());
    let command_phase = cloud_mcp_payload_text(&terminal, &["command_phase", "commandPhase"]);
    let execution_phase = cloud_mcp_payload_text(&terminal, &["execution_phase", "executionPhase"]);
    let pane_id = cloud_mcp_payload_text(
        &terminal,
        &[
            "pane_id",
            "paneId",
            "target_terminal_id",
            "targetTerminalId",
        ],
    );
    let terminal_id = cloud_mcp_payload_text(
        &terminal,
        &[
            "terminal_id",
            "terminalId",
            "target_terminal_id",
            "targetTerminalId",
        ],
    )
    .or_else(|| pane_id.clone())
    .unwrap_or_else(|| "terminal".to_string());
    let provider_session_id = cloud_mcp_payload_text_allow_empty(
        &terminal,
        &[
            "provider_session_id",
            "providerSessionId",
            "session_id",
            "sessionId",
        ],
    );
    let terminal_instance_id = cloud_mcp_payload_u64(
        &terminal,
        &[
            "terminal_instance_id",
            "terminalInstanceId",
            "instance_id",
            "instanceId",
        ],
    )
    .unwrap_or(0);
    let turn_status = cloud_mcp_payload_text(
        &terminal,
        &[
            "turn_status",
            "turnStatus",
            "latest_turn_status",
            "latestTurnStatus",
        ],
    )
    .unwrap_or_default();
    let input_ready = terminal
        .get("input_ready")
        .or_else(|| terminal.get("inputReady"))
        .and_then(Value::as_bool);
    let state_value = cloud_mcp_terminal_lifecycle_state(
        &event_type,
        &status,
        &activity_status,
        readiness.as_deref().unwrap_or_default(),
        execution_phase.as_deref().unwrap_or_default(),
        &turn_status,
    );
    let native_rail_state = cloud_mcp_payload_text(
        &terminal,
        &[
            "native_rail_state",
            "nativeRailState",
            "rail_state",
            "railState",
            "top_rail_state",
            "topRailState",
        ],
    )
    .unwrap_or_else(|| state_value.to_string());
    let native_rail_label = cloud_mcp_payload_text(
        &terminal,
        &[
            "native_rail_label",
            "nativeRailLabel",
            "rail_label",
            "railLabel",
            "top_rail_label",
            "topRailLabel",
        ],
    )
    .unwrap_or_else(|| native_rail_state.replace('_', " "));
    let display_status = cloud_mcp_payload_text(&terminal, &["display_status", "displayStatus"])
        .unwrap_or_else(|| native_rail_label.clone());
    let terminal_status = cloud_mcp_payload_text(
        &terminal,
        &[
            "terminal_status",
            "terminalStatus",
            "status_after",
            "statusAfter",
        ],
    )
    .unwrap_or_else(|| status.clone());
    let turn_status =
        cloud_mcp_terminal_lifecycle_turn_status(&event_type, &turn_status, state_value);
    let readiness = readiness.unwrap_or_else(|| {
        cloud_mcp_terminal_lifecycle_readiness(state_value, input_ready).to_string()
    });
    let status_seq = cloud_mcp_next_terminal_lifecycle_seq(
        state.inner(),
        cloud_mcp_payload_u64(&terminal, &["status_seq", "statusSeq"]),
    );
    let observed_at_ms = cloud_mcp_payload_u64(&terminal, &["observed_at_ms", "observedAtMs"])
        .unwrap_or_else(cloud_mcp_now_ms);
    let terminal_epoch = cloud_mcp_payload_text(&terminal, &["terminal_epoch", "terminalEpoch"])
        .unwrap_or_else(|| format!("{terminal_id}:{terminal_instance_id}"));
    let (workspace_runtime_seq, workspace_runtime_epoch) =
        cloud_mcp_workspace_runtime_ordering(state.inner(), &workspace);
    let terminal_nickname = cloud_mcp_terminal_nickname_text(
        &terminal,
        &[
            "terminal_nickname",
            "terminalNickname",
            "terminal_name",
            "terminalName",
            "display_name",
            "displayName",
        ],
    );
    let mut payload = json!({
        "source": "rust-diffforge-terminal-lifecycle-delta",
        "event_kind": "terminal_state_update",
        "v": 1,
        "device_id": device_profile["device_id"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "repo_id": req.repo_id,
        "workspace_root": req.root_display,
        "workspace_active": workspace_active,
        "workspace_id": req.workspace_id,
        "workspace_name": req.workspace_name,
        "workspace_status": workspace_status,
        "workspace_runtime_seq": workspace_runtime_seq,
        "workspaceRuntimeSeq": workspace_runtime_seq,
        "workspace_runtime_epoch": workspace_runtime_epoch,
        "workspaceRuntimeEpoch": workspace_runtime_epoch,
        "display_name": terminal_nickname.clone(),
        "terminal_id": terminal_id.clone(),
        "target_terminal_id": terminal_id,
        "pane_id": pane_id,
        "terminal_instance_id": terminal_instance_id,
        "terminal_index": terminal_index,
        "terminal_epoch": terminal_epoch,
        "terminal_name": terminal_nickname.clone(),
        "terminal_nickname": terminal_nickname,
        "agent_kind": agent_kind,
        "provider": cloud_mcp_payload_text(&terminal, &["provider", "agentKind", "agent_kind"]),
        "event_type": event_type,
        "state": state_value,
        "status": state_value,
        "activity_status": state_value,
        "display_status": display_status,
        "native_rail_label": native_rail_label,
        "native_rail_state": native_rail_state,
        "terminal_status": terminal_status,
        "readiness": readiness,
        "turn_status": turn_status,
        "command_phase": command_phase,
        "execution_phase": execution_phase,
        "last_known_runtime": terminal
            .get("last_known_runtime")
            .or_else(|| terminal.get("lastKnownRuntime"))
            .cloned()
            .unwrap_or(Value::Bool(false)),
        "runtime_read_only": terminal
            .get("runtime_read_only")
            .or_else(|| terminal.get("runtimeReadOnly"))
            .cloned()
            .unwrap_or(Value::Bool(false)),
        "commandable": terminal
            .get("commandable")
            .cloned()
            .unwrap_or(Value::Bool(true)),
        "connected": terminal
            .get("connected")
            .cloned()
            .unwrap_or(Value::Bool(true)),
        "native_connected": terminal
            .get("native_connected")
            .or_else(|| terminal.get("nativeConnected"))
            .cloned()
            .unwrap_or(Value::Bool(true)),
        "input_ready": input_ready,
        "turn_id": cloud_mcp_payload_text(&terminal, &["turn_id", "turnId", "latest_turn_id", "latestTurnId", "active_turn_id", "activeTurnId"]),
        "thread_id": cloud_mcp_payload_text(&terminal, &["thread_id", "threadId"]),
        "status_seq": status_seq,
        "observed_at_ms": observed_at_ms,
        "reason": reason.clone(),
        "ts_ms": cloud_mcp_now_ms(),
    });
    if let Some(provider_session_id) = provider_session_id {
        payload["provider_session_id"] = json!(provider_session_id.clone());
        payload["providerSessionId"] = json!(provider_session_id);
    }
    let reason_for_ack = reason.clone();
    log_terminal_status_event(
        "backend.cloud_mcp.terminal_state_update.publish",
        json!({
            "event_type": payload["event_type"].clone(),
            "reason": reason,
            "state": payload["state"].clone(),
            "terminal_id": payload["terminal_id"].clone(),
            "workspace_id": payload["workspace_id"].clone(),
        }),
    );
    cloud_mcp_publish_terminal_state_live_update(state.inner(), &payload, &reason_for_ack).await;
    Ok(cloud_mcp_background_sync_ack(
        "device_live_state_snapshot",
        "device_live_state_snapshot",
        &reason_for_ack,
        json!({
            "stored": {
                "stored_count": 1,
                "terminal_count": 1,
                "workspace_count": 1,
            },
            "stored_count": 1,
            "terminal_count": 1,
            "workspace_count": 1,
        }),
    ))
}

#[tauri::command]
async fn cloud_mcp_sync_device_live_workspace_servers(
    state: State<'_, CloudMcpState>,
    workspaces: Value,
    reason: Option<String>,
) -> Result<Value, String> {
    let clean_option = |value: Option<String>| {
        value
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
    };
    let reason = clean_option(reason).unwrap_or_else(|| "device_live_state_snapshot".to_string());
    let workspace_items = workspaces
        .as_array()
        .ok_or_else(|| "Workspace MCP sync requires a workspaces array.".to_string())?;
    let mut normalized_workspaces = Vec::new();
    let device_profile = cloud_mcp_desktop_device_profile();

    for (workspace_index, workspace) in workspace_items.iter().take(64).enumerate() {
        let Some(workspace_id) =
            cloud_mcp_payload_text(workspace, &["workspace_id", "workspaceId", "id"])
                .filter(|value| !value.trim().is_empty())
        else {
            continue;
        };
        let workspace_name =
            cloud_mcp_payload_text(workspace, &["workspace_name", "workspaceName", "name"])
                .unwrap_or_else(|| workspace_id.clone());
        let workspace_active = workspace
            .get("workspace_active")
            .or_else(|| workspace.get("workspaceActive"))
            .or_else(|| workspace.get("active"))
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let workspace_status = cloud_mcp_payload_text(
            workspace,
            &["workspace_status", "workspaceStatus", "status"],
        )
        .unwrap_or_else(|| {
            if workspace_active {
                "active".to_string()
            } else {
                "deactivated".to_string()
            }
        });
        let server_items = cloud_mcp_workspace_server_items(workspace);
        let servers = server_items
            .iter()
            .enumerate()
            .filter_map(|(index, server)| {
                if !server.is_object() {
                    return None;
                }
                let server_key = cloud_mcp_payload_text(
                    server,
                    &[
                        "server_key",
                        "serverKey",
                        "key",
                        "id",
                        "name",
                        "label",
                        "slug",
                        "package_ref",
                        "packageRef",
                    ],
                )
                .unwrap_or_else(|| format!("server-{}", index + 1));
                if server_key == "secrets" {
                    return None;
                }
                let name = cloud_mcp_payload_text(
                    server,
                    &["name", "label", "display_name", "displayName"],
                )
                .unwrap_or_else(|| server_key.clone());
                let name = name
                    .chars()
                    .take(CLOUD_MCP_WORKSPACE_MCP_TEXT_LIMIT)
                    .collect::<String>();
                let tools = cloud_mcp_workspace_mcp_tool_names(server);
                let tool_count = tools.len();
                Some(json!({
                    "server_key": server_key,
                    "name": name,
                    "workspace_enabled": cloud_mcp_payload_bool(server, &["workspace_enabled"], true)
                        && cloud_mcp_payload_bool(server, &["workspaceEnabled"], true),
                    "tools": tools,
                    "tool_count": tool_count,
                }))
            })
            .collect::<Vec<_>>();

        let (workspace_runtime_seq, workspace_runtime_epoch) =
            cloud_mcp_workspace_runtime_ordering(state.inner(), workspace);
        let workspace_order = cloud_mcp_payload_u64(
            workspace,
            &[
                "workspace_order",
                "workspaceOrder",
                "workspace_index",
                "workspaceIndex",
                "sort_order",
                "sortOrder",
                "order",
            ],
        )
        .unwrap_or(workspace_index as u64);
        let workspace_value = json!({
            "device_id": device_profile["device_id"].clone(),
            "workspace_id": workspace_id,
            "workspace_active": workspace_active,
            "workspace_name": workspace_name,
            "workspace_status": workspace_status,
            "workspace_runtime_seq": workspace_runtime_seq,
            "workspace_runtime_epoch": workspace_runtime_epoch,
            "workspace_order": workspace_order,
            "servers": servers,
        });
        normalized_workspaces.push(workspace_value);
    }

    let snapshot_id = format!(
        "workspace-mcp-servers-{}-{}",
        cloud_mcp_now_ms(),
        uuid::Uuid::new_v4()
    );
    let server_count = normalized_workspaces
        .iter()
        .map(|workspace| {
            workspace
                .get("servers")
                .and_then(Value::as_array)
                .map(Vec::len)
                .unwrap_or_default()
        })
        .sum::<usize>();
    let workspace_count = normalized_workspaces.len();
    let reason_for_ack = reason.clone();
    let payload = json!({
        "source": "rust-diffforge-device-live-workspace-mcp-servers",
        "event_kind": "device_live_state_snapshot",
        "client_id": CLOUD_MCP_RUST_CLIENT_ID,
        "device_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "platform": device_profile["platform"].clone(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "agent_id": "rust-diffforge",
        "agent_label": "Diff Forge Desktop",
        "reason": reason,
        "snapshot_id": snapshot_id,
        "workspace_count": workspace_count,
        "server_count": server_count,
        "workspaces": normalized_workspaces,
        "summary": "Desktop workspace MCP settings synced into the unified device live state without secret values.",
        "ts_ms": cloud_mcp_now_ms(),
    });

    {
        let mut snapshots = state.inner().runtime_snapshots.lock().await;
        snapshots.workspace_servers = Some(payload.clone());
    }
    cloud_mcp_publish_device_live_state_snapshot(state.inner(), &reason_for_ack).await;

    let sync_key = "device_live_state_snapshot".to_string();
    Ok(cloud_mcp_background_sync_ack(
        "device_live_state_snapshot",
        &sync_key,
        &reason_for_ack,
        json!({
            "stored": {
                "stored_count": server_count,
                "server_count": server_count,
                "workspace_count": workspace_count,
            },
            "stored_count": server_count,
            "server_count": server_count,
            "workspace_count": workspace_count,
        }),
    ))
}

fn cloud_mcp_workspace_payload_matches_delete(value: &Value, workspace_id: &str) -> bool {
    cloud_mcp_payload_text(value, &["workspace_id", "workspaceId", "id"])
        .as_deref()
        .map(|value| value == workspace_id)
        .unwrap_or(false)
}

fn cloud_mcp_mark_workspace_inactive_in_snapshot(
    snapshot: &mut Option<Value>,
    workspace_id: &str,
    reason: &str,
    observed_at_ms: u64,
) -> bool {
    let Some(snapshot_value) = snapshot.as_mut() else {
        return false;
    };
    let Some(object) = snapshot_value.as_object_mut() else {
        return false;
    };
    let Some(workspaces) = object.get_mut("workspaces").and_then(Value::as_array_mut) else {
        return false;
    };

    let mut changed = false;
    for workspace in workspaces {
        if !cloud_mcp_workspace_payload_matches_delete(workspace, workspace_id) {
            continue;
        }
        changed = true;
        if let Some(workspace_object) = workspace.as_object_mut() {
            workspace_object.insert("workspace_active".to_string(), json!(false));
            workspace_object.insert("workspaceActive".to_string(), json!(false));
            workspace_object.insert("workspace_status".to_string(), json!("deactivated"));
            workspace_object.insert("workspaceStatus".to_string(), json!("deactivated"));
            workspace_object.insert("status".to_string(), json!("deactivated"));
            workspace_object.insert("last_known_runtime".to_string(), json!(true));
            workspace_object.insert("lastKnownRuntime".to_string(), json!(true));
            workspace_object.insert("runtime_read_only".to_string(), json!(true));
            workspace_object.insert("runtimeReadOnly".to_string(), json!(true));
            workspace_object.insert("commandable".to_string(), json!(false));
            workspace_object.insert("reason".to_string(), json!(reason));
            workspace_object.insert("ts_ms".to_string(), json!(observed_at_ms));
            workspace_object.insert("updated_at_ms".to_string(), json!(observed_at_ms));
            workspace_object.insert("updatedAtMs".to_string(), json!(observed_at_ms));
        }
        cloud_mcp_mark_workspace_terminals_last_known_read_only(workspace);
    }
    if changed {
        object.insert("reason".to_string(), json!(reason));
        object.insert("ts_ms".to_string(), json!(observed_at_ms));
        object.insert("updated_at_ms".to_string(), json!(observed_at_ms));
        object.insert("updatedAtMs".to_string(), json!(observed_at_ms));
    }
    changed
}

fn cloud_mcp_deactivated_workspace_snapshot(
    workspace_id: &str,
    reason: &str,
    observed_at_ms: u64,
) -> Value {
    let device_profile = cloud_mcp_desktop_device_profile();
    json!({
        "source": "rust-diffforge-workspace-runtime",
        "event_kind": "device_live_state_snapshot",
        "device": device_profile.clone(),
        "device_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "platform": device_profile["platform"].clone(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "reason": reason,
        "workspace_count": 1,
        "workspaces": [{
            "workspace_id": workspace_id,
            "workspace_active": false,
            "workspaceActive": false,
            "workspace_status": "deactivated",
            "workspaceStatus": "deactivated",
            "status": "deactivated",
            "last_known_runtime": true,
            "lastKnownRuntime": true,
            "runtime_read_only": true,
            "runtimeReadOnly": true,
            "commandable": false,
            "terminals": [],
            "terminal_count": 0,
            "terminalCount": 0,
            "active_count": 0,
            "activeCount": 0,
            "reason": reason,
            "ts_ms": observed_at_ms,
            "updated_at_ms": observed_at_ms,
            "updatedAtMs": observed_at_ms,
        }],
        "ts_ms": observed_at_ms,
        "updated_at_ms": observed_at_ms,
        "updatedAtMs": observed_at_ms,
    })
}

pub(crate) async fn cloud_mcp_publish_workspace_deactivated_snapshot(
    state: &CloudMcpState,
    workspace_id: &str,
    reason: &str,
) {
    let workspace_id = workspace_id.trim();
    if workspace_id.is_empty() {
        return;
    }
    let reason = {
        let trimmed = reason.trim();
        if trimmed.is_empty() {
            "workspace_deactivate".to_string()
        } else {
            trimmed.to_string()
        }
    };
    let observed_at_ms = cloud_mcp_now_ms();
    let mut changed = false;
    {
        let mut snapshots = state.runtime_snapshots.lock().await;
        changed |= cloud_mcp_mark_workspace_inactive_in_snapshot(
            &mut snapshots.workspace_catalog,
            workspace_id,
            &reason,
            observed_at_ms,
        );
        changed |= cloud_mcp_mark_workspace_inactive_in_snapshot(
            &mut snapshots.workspace_terminals,
            workspace_id,
            &reason,
            observed_at_ms,
        );
        changed |= cloud_mcp_mark_workspace_inactive_in_snapshot(
            &mut snapshots.workspace_servers,
            workspace_id,
            &reason,
            observed_at_ms,
        );
        if !changed {
            snapshots.workspace_catalog = Some(cloud_mcp_deactivated_workspace_snapshot(
                workspace_id,
                &reason,
                observed_at_ms,
            ));
        }
    }
    cloud_mcp_publish_device_live_state_snapshot(state, &reason).await;
}

fn cloud_mcp_filter_deleted_workspace_snapshot(
    snapshot: &mut Option<Value>,
    workspace_id: &str,
    count_kind: &str,
) -> usize {
    let (removed, should_clear) = {
        let Some(snapshot_value) = snapshot.as_mut() else {
            return 0;
        };
        let Some(object) = snapshot_value.as_object_mut() else {
            return 0;
        };
        let Some(workspaces) = object.get_mut("workspaces").and_then(Value::as_array_mut) else {
            return 0;
        };

        let before = workspaces.len();
        workspaces.retain(|workspace| {
            !cloud_mcp_workspace_payload_matches_delete(workspace, workspace_id)
        });
        let removed = before.saturating_sub(workspaces.len());
        if removed == 0 {
            return 0;
        }

        let workspace_count = workspaces.len();
        let terminal_count = (count_kind == "terminals").then(|| {
            workspaces
                .iter()
                .map(|workspace| {
                    workspace
                        .get("terminals")
                        .and_then(Value::as_array)
                        .map(Vec::len)
                        .unwrap_or_default()
                })
                .sum::<usize>()
        });
        let server_count = (count_kind == "mcps").then(|| {
            workspaces
                .iter()
                .map(|workspace| {
                    workspace
                        .get("servers")
                        .and_then(Value::as_array)
                        .map(Vec::len)
                        .unwrap_or_default()
                })
                .sum::<usize>()
        });
        object.insert("workspace_count".to_string(), json!(workspace_count));
        object.insert("workspaceCount".to_string(), json!(workspace_count));
        if let Some(terminal_count) = terminal_count {
            object.insert("terminal_count".to_string(), json!(terminal_count));
            object.insert("terminalCount".to_string(), json!(terminal_count));
        }
        if let Some(server_count) = server_count {
            object.insert("server_count".to_string(), json!(server_count));
            object.insert("serverCount".to_string(), json!(server_count));
        }
        (removed, workspace_count == 0)
    };

    if should_clear {
        *snapshot = None;
    }

    removed
}

#[tauri::command]
async fn cloud_mcp_delete_workspace(
    state: State<'_, CloudMcpState>,
    repo_path: String,
    workspace_id: String,
    workspace_name: Option<String>,
    include_child_projects: Option<bool>,
) -> Result<Value, String> {
    let workspace_id = workspace_id.trim().to_string();
    if workspace_id.is_empty() {
        return Err("Workspace delete requires a workspace id.".to_string());
    }

    let root = resolve_workspace_root_directory(Some(&repo_path))?;
    let root_display = workspace_path_display(&root);
    let root_repo_id = cloud_mcp_repo_id_for_root(&root);
    let workspace_name = workspace_name
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| workspace_id.clone());
    let include_child_projects = include_child_projects.unwrap_or(false);
    let mounts = cloud_mcp_container_project_mounts(&root);
    let child_repo_ids = mounts
        .iter()
        .map(|mount| cloud_mcp_repo_id_for_root(&mount.root_path))
        .collect::<Vec<_>>();
    let mut cloud_delete_repo_ids = vec![root_repo_id.clone()];
    if include_child_projects {
        cloud_delete_repo_ids.extend(child_repo_ids.iter().cloned());
        cloud_delete_repo_ids.sort();
        cloud_delete_repo_ids.dedup();
    }

    let (removed_catalog_snapshots, removed_terminal_snapshots, removed_mcp_snapshots) = {
        let mut snapshots = state.runtime_snapshots.lock().await;
        let catalog_removed = cloud_mcp_filter_deleted_workspace_snapshot(
            &mut snapshots.workspace_catalog,
            &workspace_id,
            "catalog",
        );
        let terminal_removed = cloud_mcp_filter_deleted_workspace_snapshot(
            &mut snapshots.workspace_terminals,
            &workspace_id,
            "terminals",
        );
        let mcp_removed = cloud_mcp_filter_deleted_workspace_snapshot(
            &mut snapshots.workspace_servers,
            &workspace_id,
            "mcps",
        );
        (catalog_removed, terminal_removed, mcp_removed)
    };
    {
        let mut runtime = state.inner.lock().await;
        runtime
            .registered_workspaces
            .retain(|_, workspace| workspace.workspace_id != workspace_id);
        runtime
            .terminal_contexts
            .retain(|_, terminal| terminal.workspace_id != workspace_id);
    }

    let device_profile = cloud_mcp_desktop_device_profile();
    let payload = json!({
        "source": "rust-diffforge-workspace-delete",
        "event_kind": "workspace_deleted",
        "repo_id": root_repo_id,
        "repo_ids": cloud_delete_repo_ids,
        "workspace_id": workspace_id,
        "workspace_name": workspace_name,
        "workspace_location_fingerprint": cloud_mcp_workspace_location_fingerprint(&root),
        "workspace_root": root_display,
        "include_child_projects": include_child_projects,
        "child_repo_count": child_repo_ids.len(),
        "device": device_profile.clone(),
        "device_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "platform": device_profile["platform"].clone(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "agent_id": "rust-diffforge",
        "agent_label": "Diff Forge Desktop",
        "reason": "workspace_delete",
        "summary": "Desktop workspace deleted from Diff Forge.",
        "ts_ms": cloud_mcp_now_ms(),
    });

    let workspace_unregister_response = match cloud_mcp_ws_request_with_timeout(
        state.inner(),
        "workspace_unregister",
        &payload,
        Duration::from_secs(5),
    )
    .await
    {
        Ok(response) => json!({"ok": true, "response": response}),
        Err(error) => json!({"ok": false, "error": error}),
    };
    cloud_mcp_publish_device_live_state_snapshot(state.inner(), "workspace_deleted").await;

    let response =
        cloud_mcp_post_event_endpoint(state.inner(), "workspace_deleted", &payload).await?;
    Ok(json!({
        "ok": true,
        "workspaceId": payload["workspace_id"].clone(),
        "repoIds": payload["repo_ids"].clone(),
        "includeChildProjects": include_child_projects,
        "removedTerminalSnapshots": removed_terminal_snapshots,
        "removedMcpSnapshots": removed_mcp_snapshots,
        "removedCatalogSnapshots": removed_catalog_snapshots,
        "workspaceUnregister": workspace_unregister_response,
        "serverResponse": response,
    }))
}

#[tauri::command]
async fn cloud_mcp_sync_tokenomics_state(
    app: AppHandle,
    state: State<'_, CloudMcpState>,
    _summary: Value,
    reason: Option<String>,
    delta: Option<bool>,
) -> Result<Value, String> {
    let is_delta = delta.unwrap_or(false);
    let clean_reason = reason
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| {
            if is_delta {
                CLOUD_MCP_TOKENOMICS_DEVICE_DELTA_EVENT.to_string()
            } else {
                CLOUD_MCP_TOKENOMICS_DEVICE_SNAPSHOT_EVENT.to_string()
            }
        });
    let queued_job = cloud_mcp_enqueue_tokenomics_sync(
        app,
        state.inner(),
        clean_reason.clone(),
        !is_delta,
        false,
    )
    .await;
    Ok(cloud_mcp_background_sync_ack(
        "tokenomics_sync",
        "tokenomics:scan",
        &clean_reason,
        json!({
            "delta": is_delta,
            "full": queued_job.force_full,
            "queued_reason": queued_job.reason,
            "sync_protocol": CLOUD_MCP_TOKENOMICS_SYNC_PROTOCOL,
            "syncProtocol": CLOUD_MCP_TOKENOMICS_SYNC_PROTOCOL,
            "tokenomics_event_kind": if is_delta {
                CLOUD_MCP_TOKENOMICS_DEVICE_DELTA_EVENT
            } else {
                CLOUD_MCP_TOKENOMICS_DEVICE_SNAPSHOT_EVENT
            },
        }),
    ))
}

#[tauri::command]
async fn cloud_mcp_schedule_tokenomics_sync(
    app: AppHandle,
    state: State<'_, CloudMcpState>,
    reason: Option<String>,
    full: Option<bool>,
    resync_last_30_days: Option<bool>,
) -> Result<Value, String> {
    let clean_reason = reason
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| CLOUD_MCP_TOKENOMICS_DEVICE_DELTA_EVENT.to_string());
    let force_full = full.unwrap_or(false);
    let force_resync = resync_last_30_days.unwrap_or(false);
    cloud_mcp_background_sync_ensure_started(state.inner());
    let queued_job = cloud_mcp_enqueue_tokenomics_sync(
        app,
        state.inner(),
        clean_reason.clone(),
        force_full,
        force_resync,
    )
    .await;

    Ok(cloud_mcp_background_sync_ack(
        "tokenomics_sync",
        "tokenomics:scan",
        &clean_reason,
        json!({
            "full": queued_job.force_full,
            "resync_last_30_days": queued_job.force_resync,
            "queued_reason": queued_job.reason,
        }),
    ))
}

#[tauri::command]
async fn cloud_mcp_reset_device_tokenomics(
    app: AppHandle,
    state: State<'_, CloudMcpState>,
) -> Result<Value, String> {
    let device_profile = cloud_mcp_desktop_device_profile();
    let device_id = cloud_mcp_payload_text(
        &device_profile,
        &["device_id", "deviceId", "machine_id", "machineId"],
    )
    .map(|value| value.trim().to_string())
    .filter(|value| !value.is_empty())
    .ok_or_else(|| "Unable to determine the native desktop device id.".to_string())?;
    let (billing_scope_type, team_id) = cloud_mcp_account_scope(state.inner()).await;
    let billing_scope_key =
        tokenomics_billing_scope_key(billing_scope_type.as_str(), team_id.as_deref());
    let payload = json!({
        "source": "rust-diffforge-tokenomics-device-reset",
        "scope": "device",
        "billing_scope_type": billing_scope_type,
        "billing_scope_key": billing_scope_key.clone(),
        "team_id": team_id.clone(),
        "account_scoped": true,
        "confirm": "reset_device_tokenomics",
        "device": device_profile.clone(),
        "device_id": device_id.clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "platform": device_profile["platform"].clone(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "agent_id": "rust-diffforge",
        "agent_label": "Diff Forge Desktop",
        "reason": "tokenomics_device_cloud_reset",
        "ts_ms": cloud_mcp_now_ms(),
    });
    let response =
        cloud_mcp_post_json_endpoint(state.inner(), "/v1/tokenomics/reset-device", &payload)
            .await?;
    {
        let mut tokenomics_cursor = state.background_sync.tokenomics_cursor.lock().await;
        tokenomics_cursor.remove(payload["billing_scope_key"].as_str().unwrap_or("personal"));
    }
    let _ = cloud_mcp_tokenomics_clear_sync_state(&device_id, &billing_scope_key);
    let queued_job = cloud_mcp_enqueue_tokenomics_sync(
        app,
        state.inner(),
        "tokenomics_device_cloud_reset".to_string(),
        true,
        true,
    )
    .await;
    let mut data = cloud_mcp_response_data(&response);
    if let Some(object) = data.as_object_mut() {
        object.insert("sync_queued".to_string(), json!(true));
        object.insert(
            "sync".to_string(),
            cloud_mcp_background_sync_ack(
                "tokenomics_sync",
                "tokenomics:scan",
                "tokenomics_device_cloud_reset",
                json!({
                    "full": queued_job.force_full,
                    "resync_last_30_days": queued_job.force_resync,
                    "queued_reason": queued_job.reason,
                }),
            ),
        );
    }
    Ok(data)
}

fn cloud_mcp_tokenomics_cursor_from_summary(summary: &Value) -> Option<String> {
    let direct = summary
        .get("sync_cursor")
        .or_else(|| summary.get("syncCursor"))
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string);
    if direct.is_some() {
        return direct;
    }

    summary
        .get("hourly")
        .and_then(Value::as_array)
        .and_then(|rows| {
            rows.iter()
                .filter_map(|row| {
                    row.get("updated_at")
                        .or_else(|| row.get("updatedAt"))
                        .and_then(Value::as_str)
                        .map(str::trim)
                        .filter(|value| !value.is_empty())
                        .map(str::to_string)
                })
                .max()
        })
}

fn cloud_mcp_tag_tokenomics_summary_device(summary: &mut Value, device_profile: &Value) {
    let Some(device_id) = cloud_mcp_payload_text(
        device_profile,
        &["device_id", "deviceId", "machine_id", "machineId"],
    ) else {
        return;
    };
    let device_name = cloud_mcp_payload_text(device_profile, &["device_name", "deviceName"]);
    for key in [
        "hourly",
        "limits",
        "provider_accounts",
        "providerAccounts",
        "latest_windows",
        "latestWindows",
    ] {
        if let Some(rows) = summary.get_mut(key).and_then(Value::as_array_mut) {
            for row in rows {
                let Some(object) = row.as_object_mut() else {
                    continue;
                };
                let has_device = object
                    .get("device_id")
                    .or_else(|| object.get("deviceId"))
                    .and_then(Value::as_str)
                    .map(str::trim)
                    .is_some_and(|value| !value.is_empty());
                if !has_device {
                    object.insert("device_id".to_string(), json!(device_id.as_str()));
                    object.insert("deviceId".to_string(), json!(device_id.as_str()));
                }
                if let Some(name) = device_name.as_deref() {
                    object
                        .entry("device_name".to_string())
                        .or_insert_with(|| json!(name));
                    object
                        .entry("deviceName".to_string())
                        .or_insert_with(|| json!(name));
                }
            }
        }
    }
}

#[tauri::command]
async fn cloud_mcp_hard_reset_cloud_sqlite(
    state: State<'_, CloudMcpState>,
    repo_path: String,
    workspace_id: String,
    workspace_name: Option<String>,
    reset_scope: Option<String>,
) -> Result<Value, String> {
    let req = cloud_mcp_repo_request(
        repo_path.clone(),
        Some(workspace_id.clone()),
        workspace_name.clone(),
    );
    let device_profile = cloud_mcp_desktop_device_profile();
    let requested_reset_scope = reset_scope
        .as_deref()
        .map(str::trim)
        .filter(|scope| !scope.is_empty())
        .unwrap_or("repo")
        .to_ascii_lowercase();
    let reset_scope = match requested_reset_scope.as_str() {
        // Account scope is the "clean up the server" path: cloud-diffforge
        // wipes every per-client SQLite scope, the hot state, the workspace
        // mirror, and the deleted-ids ledger for the account, after which
        // this client resyncs everything as the authoritative copy.
        "account" | "account_full" | "account-full" => "account",
        "repo" | "repository" | "git_repo" | "git-repo" => "repo",
        "client" | "current" | "workspace" => "repo",
        _ => "repo",
    };
    let payload = json!({
        "source": "rust-diffforge-cloud-sqlite-hard-reset",
        "client_id": CLOUD_MCP_RUST_CLIENT_ID,
        "repo_id": req.repo_id,
        "repo_path": req.root_display,
        "workspace_root": req.root_display,
        "workspace_id": workspace_id,
        "workspace_name": workspace_name,
        "scope": reset_scope,
        "confirm": "hard_reset_cloud_sqlite",
        "device": device_profile.clone(),
        "device_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "platform": device_profile["platform"].clone(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "agent_id": "rust-diffforge",
        "self_agent_id": "rust-diffforge",
        "current_agent_id": "rust-diffforge",
        "ts_ms": cloud_mcp_now_ms(),
    });
    let response =
        cloud_mcp_post_json_endpoint(state.inner(), "/v1/cloud/sqlite/hard-reset", &payload)
            .await?;
    {
        let mut snapshots = state.runtime_snapshots.lock().await;
        *snapshots = CloudMcpRuntimeSnapshots::default();
    }
    Ok(cloud_mcp_response_data(&response))
}

#[tauri::command]
async fn cloud_mcp_reset_server_state(
    state: State<'_, CloudMcpState>,
    repo_path: String,
    workspace_id: String,
    workspace_name: Option<String>,
    reset_scope: Option<String>,
    repo_id_override: Option<String>,
    dry_run: Option<bool>,
) -> Result<Value, String> {
    let req = cloud_mcp_repo_request(
        repo_path.clone(),
        Some(workspace_id.clone()),
        workspace_name.clone(),
    );
    let device_profile = cloud_mcp_desktop_device_profile();
    let requested_reset_scope = reset_scope
        .as_deref()
        .map(str::trim)
        .filter(|scope| !scope.is_empty())
        .unwrap_or("repo")
        .to_ascii_lowercase();
    let reset_scope = match requested_reset_scope.as_str() {
        "repo" | "repository" | "git_repo" | "git-repo" => "repo",
        "repo_delete" | "repo-delete" | "repo_purge" | "repo-purge" => "repo_delete",
        "workspace" | "workspace_runtime" | "workspace-runtime" => "workspace",
        "account" | "account_runtime" | "account-runtime" => "account_runtime",
        _ => "repo",
    };
    // Cloud-only repos have no local checkout, so the caller may address them
    // by the repo id recorded in the account catalog instead of a local path.
    let repo_id = repo_id_override
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
        .unwrap_or_else(|| req.repo_id.clone());
    let dry_run = dry_run.unwrap_or(false);
    let payload = json!({
        "source": "rust-diffforge-server-state-reset",
        "client_id": CLOUD_MCP_RUST_CLIENT_ID,
        "repo_id": repo_id,
        "repo_path": req.root_display,
        "workspace_root": req.root_display,
        "workspace_id": workspace_id,
        "workspace_name": workspace_name,
        "scope": reset_scope,
        "dry_run": dry_run,
        "confirm": "reset_server_state",
        "preserve": {
            "devices": true,
            "billing": true,
            "tokenomics": true,
        },
        "device": device_profile.clone(),
        "device_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "platform": device_profile["platform"].clone(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "agent_id": "rust-diffforge",
        "self_agent_id": "rust-diffforge",
        "current_agent_id": "rust-diffforge",
        "ts_ms": cloud_mcp_now_ms(),
    });
    let response =
        cloud_mcp_post_json_endpoint(state.inner(), "/v1/cloud/server-reset", &payload).await?;
    if !dry_run {
        let mut snapshots = state.runtime_snapshots.lock().await;
        *snapshots = CloudMcpRuntimeSnapshots::default();
    }
    Ok(cloud_mcp_response_data(&response))
}

