fn cloud_mcp_account_skills_cache_path() -> Option<PathBuf> {
    cloud_mcp_local_data_file_path("account-skills.md")
}

fn cloud_mcp_cache_account_skills(skills_md: &str) {
    if let Some(path) = cloud_mcp_account_skills_cache_path() {
        if let Some(parent) = path.parent() {
            let _ = fs::create_dir_all(parent);
        }
        let _ = fs::write(path, skills_md);
    }
}

fn cloud_mcp_cached_account_skills() -> String {
    cloud_mcp_account_skills_cache_path()
        .and_then(|path| fs::read_to_string(path).ok())
        .unwrap_or_default()
}

fn cloud_mcp_tools_base_payload(source: &str) -> Value {
    let device_profile = cloud_mcp_desktop_device_profile();
    json!({
        "source": source,
        "client_id": CLOUD_MCP_RUST_CLIENT_ID,
        "device": device_profile.clone(),
        "device_id": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "platform": device_profile["platform"].clone(),
        "form_factor": device_profile["form_factor"].clone(),
        "client_kind": device_profile["client_kind"].clone(),
        "agent_id": "rust-diffforge",
        "ts_ms": cloud_mcp_now_ms(),
    })
}

#[tauri::command]
async fn cloud_mcp_get_account_tools(state: State<'_, CloudMcpState>) -> Result<Value, String> {
    let payload = cloud_mcp_tools_base_payload("rust-diffforge-account-tools");
    match cloud_mcp_post_json_endpoint(state.inner(), "/v1/tools/account", &payload).await {
        Ok(response) => {
            let data = cloud_mcp_response_data(&response);
            if let Some(skills_md) = data
                .get("skills")
                .and_then(|skills| skills.get("skills_md").or_else(|| skills.get("skillsMd")))
                .and_then(Value::as_str)
            {
                cloud_mcp_cache_account_skills(skills_md);
            }
            Ok(data)
        }
        Err(error) => {
            // Offline fallback: keep the tools view usable with cached skills.
            let cached = cloud_mcp_cached_account_skills();
            Ok(json!({
                "kind": "account_tools",
                "offline": true,
                "error": error,
                "skills": {
                    "skills_md": cached.clone(),
                    "skillsMd": cached,
                    "revision": Value::Null,
                },
                "clis": [],
                "mcps": [],
                "servers": [],
            }))
        }
    }
}

#[tauri::command]
async fn cloud_mcp_save_account_skills(
    state: State<'_, CloudMcpState>,
    skills_md: String,
    base_revision: Option<i64>,
) -> Result<Value, String> {
    let mut payload = cloud_mcp_tools_base_payload("rust-diffforge-account-skills");
    if let Some(object) = payload.as_object_mut() {
        object.insert("skills_md".to_string(), json!(skills_md.clone()));
        object.insert("skillsMd".to_string(), json!(skills_md.clone()));
        if let Some(base_revision) = base_revision {
            object.insert("base_revision".to_string(), json!(base_revision));
            object.insert("baseRevision".to_string(), json!(base_revision));
        }
    }
    let response =
        cloud_mcp_post_json_endpoint(state.inner(), "/v1/tools/skills", &payload).await?;
    cloud_mcp_cache_account_skills(&skills_md);
    Ok(cloud_mcp_response_data(&response))
}

#[tauri::command]
async fn cloud_mcp_report_cli_snapshot(
    state: State<'_, CloudMcpState>,
    clis: Value,
) -> Result<Value, String> {
    let mut payload = cloud_mcp_tools_base_payload("rust-diffforge-cli-snapshot");
    if let Some(object) = payload.as_object_mut() {
        object.insert("clis".to_string(), clis);
    }
    {
        let mut snapshots = state.inner().runtime_snapshots.lock().await;
        snapshots.cli_states = Some(payload.clone());
    }
    cloud_mcp_publish_device_live_state_snapshot(state.inner(), "cli_snapshot").await;
    let response =
        cloud_mcp_post_json_endpoint(state.inner(), "/v1/tools/cli-snapshot", &payload).await?;
    Ok(cloud_mcp_response_data(&response))
}

#[tauri::command]
async fn cloud_mcp_record_voice_plan_task_status(
    state: State<'_, CloudMcpState>,
    repo_path: String,
    workspace_id: String,
    workspace_name: Option<String>,
    status: Value,
) -> Result<Value, String> {
    let req = cloud_mcp_repo_request(
        repo_path.clone(),
        Some(workspace_id.clone()),
        workspace_name.clone(),
    );
    let mut payload = match status {
        Value::Object(object) => Value::Object(object),
        _ => return Err("Voice plan task status payload must be an object.".to_string()),
    };
    let plan_run_id = cloud_mcp_payload_text(&payload, &["planRunId"])
        .or_else(|| cloud_mcp_payload_text(&payload, &["plan_run_id"]))
        .or_else(|| cloud_mcp_payload_text(&payload, &["runId"]))
        .or_else(|| cloud_mcp_payload_text(&payload, &["run_id"]));
    let plan_task_id = cloud_mcp_payload_text(&payload, &["planTaskId"])
        .or_else(|| cloud_mcp_payload_text(&payload, &["plan_task_id"]))
        .or_else(|| cloud_mcp_payload_text(&payload, &["taskId"]))
        .or_else(|| cloud_mcp_payload_text(&payload, &["task_id"]));
    let plan_stage = cloud_mcp_payload_text(&payload, &["planStage"])
        .or_else(|| cloud_mcp_payload_text(&payload, &["plan_stage"]))
        .or_else(|| cloud_mcp_payload_text(&payload, &["stage"]));
    let prompt_event_id = cloud_mcp_payload_text(&payload, &["promptEventId"])
        .or_else(|| cloud_mcp_payload_text(&payload, &["prompt_event_id"]));
    let plan_step_ordinal = payload
        .get("planStepOrdinal")
        .or_else(|| payload.get("plan_step_ordinal"))
        .or_else(|| payload.get("stepOrdinal"))
        .or_else(|| payload.get("step_ordinal"))
        .cloned();
    if let Some(object) = payload.as_object_mut() {
        object.insert("event_kind".to_string(), json!("voice_plan_task_status"));
        object.insert("repo_id".to_string(), json!(req.repo_id.clone()));
        object.insert("repoId".to_string(), json!(req.repo_id.clone()));
        object.insert("repo_path".to_string(), json!(req.root_display.clone()));
        object.insert("repoPath".to_string(), json!(req.root_display.clone()));
        object.insert(
            "workspace_root".to_string(),
            json!(req.root_display.clone()),
        );
        object.insert("workspaceRoot".to_string(), json!(req.root_display.clone()));
        object.insert("workspace_id".to_string(), json!(workspace_id.clone()));
        object.insert("workspaceId".to_string(), json!(workspace_id.clone()));
        if let Some(name) = workspace_name {
            object.insert("workspace_name".to_string(), json!(name));
        }
        if let Some(value) = plan_run_id.as_deref() {
            for key in ["planRunId", "plan_run_id", "runId", "run_id"] {
                object.insert(key.to_string(), json!(value));
            }
        }
        if let Some(value) = plan_task_id.as_deref() {
            for key in ["planTaskId", "plan_task_id", "taskId", "task_id"] {
                object.insert(key.to_string(), json!(value));
            }
        }
        if let Some(value) = plan_stage.as_deref() {
            for key in ["planStage", "plan_stage", "stage"] {
                object.insert(key.to_string(), json!(value));
            }
        }
        if let Some(value) = plan_step_ordinal {
            for key in [
                "planStepOrdinal",
                "plan_step_ordinal",
                "stepOrdinal",
                "step_ordinal",
            ] {
                object.insert(key.to_string(), value.clone());
            }
        }
        if let Some(value) = prompt_event_id.as_deref() {
            for key in ["promptEventId", "prompt_event_id"] {
                object.insert(key.to_string(), json!(value));
            }
        }
    }

    log_terminal_status_event(
        "backend.voice_plan_task_status.send",
        json!({
            "endpoint": "voice_plan_task_status",
            "payload": payload.clone(),
            "workspace_id": workspace_id,
        }),
    );
    let result =
        cloud_mcp_post_event_endpoint(state.inner(), "voice_plan_task_status", &payload).await;
    match &result {
        Ok(value) => log_terminal_status_event(
            "backend.voice_plan_task_status.result",
            json!({
                "endpoint": "voice_plan_task_status",
                "ok": true,
                "result": value,
            }),
        ),
        Err(error) => log_terminal_status_event(
            "backend.voice_plan_task_status.error",
            json!({
                "endpoint": "voice_plan_task_status",
                "error": clean_terminal_telemetry_text(error),
                "payload": payload,
            }),
        ),
    }
    result
}

#[tauri::command]
async fn cloud_mcp_update_voice_plan_steps(
    app: AppHandle,
    state: State<'_, CloudMcpState>,
    repo_path: String,
    workspace_id: String,
    workspace_name: Option<String>,
    update: Value,
) -> Result<Value, String> {
    let req = cloud_mcp_repo_request(
        repo_path.clone(),
        Some(workspace_id.clone()),
        workspace_name.clone(),
    );
    let mut payload = match update {
        Value::Object(object) => Value::Object(object),
        _ => return Err("Voice plan step update payload must be an object.".to_string()),
    };
    if let Some(object) = payload.as_object_mut() {
        object.insert("event_kind".to_string(), json!("voice_plan_step_update"));
        object.insert("repo_id".to_string(), json!(req.repo_id.clone()));
        object.insert("repoId".to_string(), json!(req.repo_id.clone()));
        object.insert("repo_path".to_string(), json!(req.root_display.clone()));
        object.insert("repoPath".to_string(), json!(req.root_display.clone()));
        object.insert(
            "workspace_root".to_string(),
            json!(req.root_display.clone()),
        );
        object.insert("workspaceRoot".to_string(), json!(req.root_display.clone()));
        object.insert("workspace_id".to_string(), json!(workspace_id.clone()));
        object.insert("workspaceId".to_string(), json!(workspace_id.clone()));
        if let Some(name) = workspace_name {
            object.insert("workspace_name".to_string(), json!(name));
        }
    }

    log_terminal_status_event(
        "backend.voice_plan_step_update.send",
        json!({
            "endpoint": "voice_plan_step_update",
            "payload": payload.clone(),
            "workspace_id": workspace_id,
        }),
    );
    let result =
        cloud_mcp_post_event_endpoint(state.inner(), "voice_plan_step_update", &payload).await;
    match &result {
        Ok(value) => {
            log_terminal_status_event(
                "backend.voice_plan_step_update.result",
                json!({
                    "endpoint": "voice_plan_step_update",
                    "ok": true,
                    "result": value,
                }),
            );
            let _ = app.emit(
                VOICE_PLAN_SERVER_RESULT_EVENT,
                json!({
                    "result": value,
                    "source": "backend_voice_plan_step_update",
                    "workspaceId": workspace_id,
                }),
            );
        }
        Err(error) => log_terminal_status_event(
            "backend.voice_plan_step_update.error",
            json!({
                "endpoint": "voice_plan_step_update",
                "error": clean_terminal_telemetry_text(error),
                "payload": payload,
            }),
        ),
    }
    result
}

fn cloud_mcp_architecture_payload_base(
    _req: &CloudMcpRepoRequest,
    _workspace_id: &str,
    _workspace_name: Option<&str>,
    reason: &str,
) -> Value {
    let device_profile = cloud_mcp_desktop_device_profile();
    json!({
        "source": "rust-diffforge-architecture",
        "reason": reason,
        "scope": "account",
        "architecture_scope": "global",
        "architectureScope": "global",
        "repo_id": ARCHITECTURE_GLOBAL_REPO_ID,
        "repoId": ARCHITECTURE_GLOBAL_REPO_ID,
        "workspace_id": ARCHITECTURE_GLOBAL_WORKSPACE_ID,
        "workspaceId": ARCHITECTURE_GLOBAL_WORKSPACE_ID,
        "workspace_name": "Global",
        "workspaceName": "Global",
        "device": device_profile.clone(),
        "device_id": device_profile["device_id"].clone(),
        "deviceId": device_profile["device_id"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "machineId": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "ts_ms": cloud_mcp_now_ms(),
    })
}

fn cloud_mcp_architecture_graph_id(graph: &Value) -> String {
    cloud_mcp_payload_text(
        graph,
        &[
            "id",
            "architecture_id",
            "architectureId",
            "graph_id",
            "graphId",
        ],
    )
    .unwrap_or_default()
}

fn cloud_mcp_architecture_local_graph_id(graph: &Value) -> String {
    cloud_mcp_payload_text(graph, &["local_graph_id", "localGraphId"])
        .unwrap_or_else(|| cloud_mcp_architecture_graph_id(graph))
}

fn cloud_mcp_architecture_graph_for_global_sync(mut graph: Value) -> Value {
    let local_graph_id = cloud_mcp_architecture_local_graph_id(&graph);
    if local_graph_id.is_empty() {
        return graph;
    }
    if let Some(object) = graph.as_object_mut() {
        object.insert("id".to_string(), json!(local_graph_id.clone()));
        object.insert("architecture_id".to_string(), json!(local_graph_id.clone()));
        object.insert("architectureId".to_string(), json!(local_graph_id.clone()));
        object.insert("graph_id".to_string(), json!(local_graph_id.clone()));
        object.insert("graphId".to_string(), json!(local_graph_id.clone()));
        object.insert("cloud_graph_id".to_string(), json!(local_graph_id.clone()));
        object.insert("cloudGraphId".to_string(), json!(local_graph_id.clone()));
        object.insert("local_graph_id".to_string(), json!(local_graph_id.clone()));
        object.insert("localGraphId".to_string(), json!(local_graph_id));
        object.insert(
            "architecture_scope_id".to_string(),
            json!(ARCHITECTURE_GLOBAL_REPO_ID),
        );
        object.insert(
            "architectureScopeId".to_string(),
            json!(ARCHITECTURE_GLOBAL_REPO_ID),
        );
        object.insert("scope_id".to_string(), json!(ARCHITECTURE_GLOBAL_REPO_ID));
        object.insert("scopeId".to_string(), json!(ARCHITECTURE_GLOBAL_REPO_ID));
        object.insert("architecture_scope_kind".to_string(), json!("global"));
        object.insert("architectureScopeKind".to_string(), json!("global"));
        object.insert("scope_kind".to_string(), json!("global"));
        object.insert("scopeKind".to_string(), json!("global"));
        object.insert("architecture_scope_name".to_string(), json!("Global"));
        object.insert("architectureScopeName".to_string(), json!("Global"));
        object.insert("scope_name".to_string(), json!("Global"));
        object.insert("scopeName".to_string(), json!("Global"));
        object.insert("architecture_account_path".to_string(), json!("global"));
        object.insert("architectureAccountPath".to_string(), json!("global"));
        object.insert("account_path".to_string(), json!("global"));
        object.insert("accountPath".to_string(), json!("global"));
        object.insert("account_path_parts".to_string(), json!(["Global"]));
        object.insert("accountPathParts".to_string(), json!(["Global"]));
    }
    graph
}

fn cloud_mcp_architecture_graph_with_source(mut graph: Value) -> Value {
    let Some(file_path) = cloud_mcp_payload_text(&graph, &["file_path", "filePath"]) else {
        return graph;
    };
    let path = Path::new(&file_path);
    let Ok(metadata) = fs::metadata(path) else {
        return graph;
    };
    if !metadata.is_file() || metadata.len() > ARCHITECTURE_GRAPH_MAX_BYTES {
        return graph;
    }
    let Ok(source) = fs::read_to_string(path) else {
        return graph;
    };
    let hash = architecture_content_hash(&source);
    let source_format = if path
        .extension()
        .and_then(|value| value.to_str())
        .map(|value| value.eq_ignore_ascii_case("json"))
        .unwrap_or(false)
    {
        "json"
    } else {
        "eraserDsl"
    };
    if let Some(object) = graph.as_object_mut() {
        object.insert("source".to_string(), json!(source));
        object.insert("sourceFormat".to_string(), json!(source_format));
        object.insert("source_format".to_string(), json!(source_format));
        object.insert("contentHash".to_string(), json!(hash.clone()));
        object.insert("content_hash".to_string(), json!(hash.clone()));
        object.insert("contentRevision".to_string(), json!(hash.clone()));
        object.insert("content_revision".to_string(), json!(hash));
    }
    graph
}

fn cloud_mcp_push_account_architecture_graph(
    output: &mut Vec<Value>,
    seen: &mut HashSet<String>,
    graph: Value,
) {
    let graph = cloud_mcp_prepare_architecture_graph(cloud_mcp_architecture_graph_for_global_sync(
        cloud_mcp_architecture_graph_with_source(graph),
    ));
    let graph_id = cloud_mcp_architecture_graph_id(&graph);
    if graph_id.is_empty() || !seen.insert(graph_id) {
        return;
    }
    output.push(graph);
}

fn cloud_mcp_collect_account_architecture_graphs(fallback_graphs: Value) -> Vec<Value> {
    let mut graphs = Vec::new();
    let mut seen = HashSet::new();

    if let Ok(global_root) = architecture_global_root_dir() {
        if let Ok(list) = architecture_graphs_list_value(workspace_path_display(&global_root)) {
            for graph in cloud_mcp_architecture_graphs_payload(list) {
                cloud_mcp_push_account_architecture_graph(&mut graphs, &mut seen, graph);
            }
        }
    }

    for graph in cloud_mcp_architecture_graphs_payload(fallback_graphs) {
        cloud_mcp_push_account_architecture_graph(&mut graphs, &mut seen, graph);
    }

    graphs
}

fn cloud_mcp_architecture_graphs_payload(value: Value) -> Vec<Value> {
    if let Some(items) = value.as_array() {
        return items.clone();
    }
    for key in ["graphs", "architectures", "items"] {
        if let Some(items) = value.get(key).and_then(Value::as_array) {
            return items.clone();
        }
    }
    value
        .get("graph")
        .or_else(|| value.get("architecture"))
        .or_else(|| value.get("item"))
        .filter(|item| item.is_object())
        .cloned()
        .or_else(|| value.is_object().then(|| value.clone()))
        .into_iter()
        .collect()
}

fn cloud_mcp_architecture_refs_array(value: &Value) -> Vec<Value> {
    if let Some(items) = value.as_array() {
        return items.clone();
    }
    for key in ["refs", "graphs", "architectures", "items"] {
        if let Some(items) = value.get(key).and_then(Value::as_array) {
            return items.clone();
        }
    }
    value
        .get("ref")
        .or_else(|| value.get("graph"))
        .or_else(|| value.get("architecture"))
        .or_else(|| value.get("item"))
        .filter(|item| item.is_object())
        .cloned()
        .or_else(|| value.is_object().then(|| value.clone()))
        .into_iter()
        .collect()
}

fn cloud_mcp_prepare_architecture_graph(mut graph: Value) -> Value {
    let hash = graph
        .get("contentHash")
        .or_else(|| graph.get("content_hash"))
        .and_then(Value::as_str)
        .map(str::to_string)
        .or_else(|| {
            graph
                .get("source")
                .and_then(Value::as_str)
                .map(architecture_content_hash)
        });
    if let Some(object) = graph.as_object_mut() {
        if let Some(hash) = hash {
            object
                .entry("contentHash".to_string())
                .or_insert_with(|| json!(hash.clone()));
            object
                .entry("content_hash".to_string())
                .or_insert_with(|| json!(hash.clone()));
            object
                .entry("contentRevision".to_string())
                .or_insert_with(|| json!(hash.clone()));
            object
                .entry("content_revision".to_string())
                .or_insert_with(|| json!(hash));
        }
        object
            .entry("sourceFormat".to_string())
            .or_insert_with(|| json!("eraserDsl"));
        object
            .entry("source_format".to_string())
            .or_insert_with(|| json!("eraserDsl"));
    }
    graph
}

fn cloud_mcp_architecture_hydrated_graph(mut item: Value) -> Option<Value> {
    let source = cloud_mcp_payload_text(&item, &["source", "source_text", "sourceText"])?;
    let graph_id = cloud_mcp_payload_text(
        &item,
        &[
            "id",
            "architecture_id",
            "architectureId",
            "graph_id",
            "graphId",
        ],
    )?;
    let local_graph_id = cloud_mcp_payload_text(&item, &["local_graph_id", "localGraphId"])
        .unwrap_or_else(|| graph_id.clone());
    let object = item.as_object_mut()?;
    object.insert("id".to_string(), json!(local_graph_id.clone()));
    object.insert("local_graph_id".to_string(), json!(local_graph_id.clone()));
    object.insert("localGraphId".to_string(), json!(local_graph_id));
    object.insert("cloud_graph_id".to_string(), json!(graph_id.clone()));
    object.insert("cloudGraphId".to_string(), json!(graph_id.clone()));
    object.insert("architecture_id".to_string(), json!(graph_id.clone()));
    object.insert("architectureId".to_string(), json!(graph_id));
    object.insert("source".to_string(), json!(source));
    object
        .entry("sourceFormat".to_string())
        .or_insert_with(|| json!("eraserDsl"));
    object
        .entry("source_format".to_string())
        .or_insert_with(|| json!("eraserDsl"));
    Some(item)
}

#[tauri::command]
async fn cloud_mcp_get_workspace_architectures(
    state: State<'_, CloudMcpState>,
    repo_path: String,
    workspace_id: Option<String>,
    workspace_name: Option<String>,
    scope_repo_id: Option<String>,
    scope_git_repo_identity_id: Option<String>,
) -> Result<Value, String> {
    let req = cloud_mcp_repo_request(repo_path, workspace_id.clone(), workspace_name.clone());
    let mut payload = cloud_mcp_architecture_payload_base(
        &req,
        ARCHITECTURE_GLOBAL_WORKSPACE_ID,
        Some("Global"),
        "architecture_index_pull",
    );
    let _ = (scope_repo_id, scope_git_repo_identity_id);
    if let Some(object) = payload.as_object_mut() {
        object.insert("architecture_scope".to_string(), json!("global"));
        object.insert("architectureScope".to_string(), json!("global"));
    }
    let response =
        cloud_mcp_post_json_endpoint(state.inner(), "/v1/workspace/architectures/list", &payload)
            .await?;
    Ok(response.get("data").cloned().unwrap_or(response))
}

