    #[test]
    fn account_live_state_merge_preserves_registered_device_inventory() {
        let previous = json!({
            "registered_devices": {
                "source": "next_agents_devices",
                "count": 2,
                "registered_count": 2,
                "items": [
                    {
                        "device_id": "macos-24c",
                        "display_name": "Syed's MacBook Air",
                        "registered": true,
                        "connected": true,
                        "native_connected": true,
                        "web_connected": true,
                        "workspaces": [{ "id": "ws-desktop" }],
                        "agents": [{ "id": "agent-desktop" }]
                    },
                    {
                        "device_id": "web-android-mobile-samsung-galaxy-s23-ultra",
                        "display_name": "Samsung Galaxy S23 Ultra",
                        "platform": "android",
                        "form_factor": "mobile",
                        "registered": true,
                        "connected": false,
                        "native_connected": false,
                        "web_connected": false
                    }
                ],
                "workspaces": [{ "id": "ws-desktop" }],
                "agents": [{ "id": "agent-desktop" }]
            }
        });
        let next = json!({
            "registered_devices": {
                "source": "cloud_hot_state",
                "count": 1,
                "registered_count": 1,
                "items": [
                    {
                        "device_id": "macos-24c",
                        "display_name": "Syed's MacBook Air",
                        "registered": true,
                        "connected": true,
                        "native_connected": true,
                        "web_connected": true,
                        "workspaces": [],
                        "agents": []
                    }
                ],
                "workspaces": [],
                "agents": []
            },
            "registered_device_count": 1,
            "known_device_count": 1
        });

        let merged = cloud_mcp_merge_account_live_state_snapshot(Some(&previous), next);
        let registry = merged
            .get("registered_devices")
            .expect("merged registry alias");
        let items = registry
            .get("items")
            .and_then(Value::as_array)
            .expect("merged items");

        assert_eq!(items.len(), 2);
        assert!(items.iter().any(|item| {
            item.get("display_name").and_then(Value::as_str)
                == Some("Samsung Galaxy S23 Ultra")
        }));
        assert_eq!(
            registry.get("workspaces").and_then(Value::as_array).map(Vec::len),
            Some(1)
        );
        assert_eq!(
            registry.get("agents").and_then(Value::as_array).map(Vec::len),
            Some(1)
        );
        assert_eq!(merged.get("registered_device_count").and_then(Value::as_u64), Some(2));
        assert_eq!(merged.get("known_device_count").and_then(Value::as_u64), Some(2));
        assert_eq!(merged.get("registeredDevices"), merged.get("registered_devices"));
        assert_eq!(merged.get("deviceRegistry"), merged.get("registered_devices"));
    }

    struct ScopedCloudMcpEnv {
        key: &'static str,
        previous: Option<std::ffi::OsString>,
    }

    impl ScopedCloudMcpEnv {
        fn set(key: &'static str, value: &Path) -> Self {
            let previous = env::var_os(key);
            env::set_var(key, value);
            Self { key, previous }
        }
    }

    impl Drop for ScopedCloudMcpEnv {
        fn drop(&mut self) {
            if let Some(previous) = self.previous.take() {
                env::set_var(self.key, previous);
            } else {
                env::remove_var(self.key);
            }
        }
    }

    fn test_cloud_root(prefix: &str) -> PathBuf {
        let suffix = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .map(|duration| duration.as_nanos())
            .unwrap_or(0);
        env::temp_dir().join(format!("{prefix}-{suffix}"))
    }

    fn create_cloud_package_project(root: &Path) {
        fs::create_dir_all(root.join("src")).unwrap();
        fs::write(root.join("package.json"), "{}\n").unwrap();
        fs::write(root.join("src").join("app.js"), "console.log('ok');\n").unwrap();
    }

    fn init_cloud_git_repo(root: &Path) -> bool {
        fs::create_dir_all(root).unwrap();
        Command::new("git")
            .arg("-C")
            .arg(root)
            .arg("init")
            .output()
            .map(|output| output.status.success())
            .unwrap_or(false)
    }

    #[test]
    fn agent_session_summary_keeps_latest_three_todos_raw() {
        let session = json!({
            "key": "session-cache-1",
            "providerSessionId": "provider-session-1",
            "agentKind": "codex",
            "provider": "codex",
        });
        let rows = (0..23)
            .map(|index| {
                json!({
                    "todoId": format!("todo-{index}"),
                    "status": if index % 2 == 0 { "completed" } else { "running" },
                    "text": format!("Task number {index}"),
                })
            })
            .collect::<Vec<_>>();

        let summary = cloud_mcp_agent_session_summary_from_rows(&session, &rows, 1234);

        assert_eq!(summary["todoCount"].as_u64(), Some(23));
        assert_eq!(summary["summaryItemCount"].as_u64(), Some(5));
        assert_eq!(summary["chunkCount"].as_u64(), Some(2));
        let chunks = summary["chunks"].as_array().unwrap();
        assert_eq!(chunks[0]["todoCount"].as_u64(), Some(10));
        assert_eq!(chunks[1]["todoCount"].as_u64(), Some(10));
        assert_eq!(summary["compressionJobs"].as_array().map(Vec::len), Some(2));
        let items = summary["summaryItems"].as_array().unwrap();
        assert_eq!(items[2]["itemKind"].as_str(), Some("raw_todo"));
        assert_eq!(items[2]["todoId"].as_str(), Some("todo-20"));
        assert_eq!(items[4]["todoId"].as_str(), Some("todo-22"));
        assert_eq!(
            chunks[0]["compressionStatus"].as_str(),
            Some("pending_cloud_llm")
        );
    }

