        let thirteen = cloud_mcp_agent_session_summary_from_rows(&session, &thirteen_rows, 1234);
        assert_eq!(thirteen["chunkCount"].as_u64(), Some(1));
        assert_eq!(thirteen["summaryItemCount"].as_u64(), Some(4));
