pub(crate) fn cloud_mcp_forward_agent_upload_asset(
    _repo_path: Option<&str>,
    _workspace_id: Option<&str>,
    base_url_override: Option<&str>,
    input: &Value,
) -> Result<Value, String> {
    let mut input = input.clone();
    let path = match cloud_mcp_payload_text(&input, &["path", "local_path", "localPath"]) {
        Some(path) => path,
        None => {
            let asset_id = cloud_mcp_payload_text(&input, &["asset_id", "assetId", "id"])
                .ok_or_else(|| "upload_asset requires asset_id or path/local_path.".to_string())?;
            let row = cloud_mcp_asset_row_with_local_copy(&asset_id)?;
            let local_path = cloud_mcp_payload_text(&row, &["local_path", "localPath", "path"])
                .ok_or_else(|| "Asset has no local copy on this device to upload.".to_string())?;
            let object = input
                .as_object_mut()
                .ok_or_else(|| "upload_asset arguments must be an object.".to_string())?;
            object.insert("path".to_string(), json!(local_path.clone()));
            object.insert("local_path".to_string(), json!(local_path.clone()));
            object.insert("localPath".to_string(), json!(local_path.clone()));
            for key in [
                "asset_id",
                "assetId",
                "name",
                "filename",
                "kind",
                "mime_type",
                "mimeType",
                "size_bytes",
                "sizeBytes",
                "sha256",
                "metadata",
                "source_kind",
                "sourceKind",
            ] {
                if !object.contains_key(key) {
                    if let Some(value) = row.get(key) {
                        object.insert(key.to_string(), value.clone());
                    }
                }
            }
            local_path
        }
    };
    diffforge_reject_untracked_asset_path_for_tracking(Path::new(&path), "upload a tracked asset")?;
    let req = cloud_mcp_asset_scope_request();
    let base_url = base_url_override
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(|value| value.trim_end_matches('/').to_string())
        .unwrap_or_else(cloud_mcp_base_url);
    let row = cloud_mcp_asset_local_row_with_input(&req, "", None, Path::new(&path), &input)?;
    cloud_mcp_asset_store_local_row(&row)?;
    let asset_id = cloud_mcp_payload_text(&row, &["asset_id", "assetId"]).unwrap_or_default();
    let local_path = cloud_mcp_payload_text(&row, &["local_path", "localPath", "path"])
        .ok_or_else(|| "upload_asset could not resolve a local path.".to_string())?;
    let mut payload = cloud_mcp_asset_registration_payload_from_row("agent_asset_upload", &row);
    let mut attached_process_reset = false;
    if let Some(object) = payload.as_object_mut() {
        attached_process_reset = cloud_mcp_asset_attach_process_reset_flag(object);
        if let Some(cloud_id) = cloud_mcp_payload_text(&input, &["cloud_id", "cloudId"]) {
            object.insert("cloud_id".to_string(), json!(cloud_id));
            object.insert("cloudId".to_string(), json!(cloud_id));
        }
    }
    let response = match cloud_mcp_proxy_post_json_endpoint(
        &base_url,
        "/v1/assets/prepare-upload",
        &payload.to_string(),
    ) {
        Ok(response) => {
            cloud_mcp_asset_finish_process_reset(attached_process_reset, true);
            response
        }
        Err(error) => {
            cloud_mcp_asset_finish_process_reset(attached_process_reset, false);
            return Err(error);
        }
    };
    let parsed = serde_json::from_str::<Value>(&response)
        .unwrap_or_else(|_| json!({"raw_response": response}));
    let prepare = parsed.get("data").cloned().unwrap_or(parsed);
    cloud_mcp_update_asset_library_from_response(
        "agent_asset_prepare_upload",
        Some("/v1/assets/prepare-upload"),
        &payload,
        &prepare,
    );
    let upload_required = prepare
        .get("upload_required")
        .or_else(|| prepare.get("uploadRequired"))
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let upload = if upload_required {
        let upload_url = cloud_mcp_payload_text(&prepare, &["upload_url", "uploadUrl"])
            .ok_or_else(|| "Cloud did not return an asset upload URL.".to_string())?;
        let direct_transfer = cloud_mcp_asset_direct_presigned(&prepare);
        let upload_path = if direct_transfer {
            cloud_mcp_payload_text(&prepare, &["upload_path", "uploadPath"])
                .unwrap_or_else(|| upload_url.clone())
        } else {
            cloud_mcp_payload_text(&prepare, &["upload_path", "uploadPath"])
                .ok_or_else(|| "Cloud did not return an asset upload path.".to_string())?
        };
        let http_target = if direct_transfer {
            CloudMcpAssetHttpTarget {
                url: upload_url.clone(),
                route_token: None,
            }
        } else {
            cloud_mcp_asset_http_target_blocking(&base_url, &upload_path)?
        };
        let mut attempts: Vec<(String, reqwest::header::HeaderMap)> = Vec::new();
        if direct_transfer {
            attempts.push((http_target.url.clone(), reqwest::header::HeaderMap::new()));
        } else {
            let token = cloud_mcp_process_authorization_bearer();
            attempts.push((
                http_target.url.clone(),
                cloud_mcp_asset_http_headers(token.as_deref(), http_target.route_token.as_deref())?,
            ));
        }
        let transfer_id = cloud_mcp_asset_prepare_transfer_id(&prepare, "upload")?;
        let transfer_cloud_id = cloud_mcp_payload_text(&prepare, &["cloud_id", "cloudId"])
            .or_else(|| cloud_mcp_payload_text(&input, &["cloud_id", "cloudId"]))
            .unwrap_or_else(|| "diffforge-ai-cloud".to_string());
        let bytes_total = cloud_mcp_payload_i64(&prepare, &["size_bytes", "sizeBytes"])
            .or_else(|| Some(cloud_mcp_asset_row_i64(&row, &["size_bytes", "sizeBytes"])))
            .unwrap_or_default();
        let (upload_reporter, progress_thread) = if direct_transfer {
            let (progress_tx, mut progress_rx) = mpsc::unbounded_channel::<Value>();
            let progress_base_url = base_url.clone();
            let progress_thread = std::thread::spawn(move || {
                while let Some(progress) = progress_rx.blocking_recv() {
                    let _ = cloud_mcp_proxy_post_json_endpoint(
                        &progress_base_url,
                        "/v1/assets/report-transfer-progress",
                        &progress.to_string(),
                    );
                }
            });
            (Some(progress_tx), Some(progress_thread))
        } else {
            (None, None)
        };
        let attempt_count = attempts.len();
        let mut upload_result: Result<Value, String> =
            Err("Asset upload did not start.".to_string());
        for (attempt_index, (attempt_url, attempt_headers)) in attempts.into_iter().enumerate() {
            upload_result = cloud_mcp_upload_asset_streaming_blocking(
                attempt_url,
                attempt_headers,
                Path::new(&local_path),
                asset_id.clone(),
                transfer_id.clone(),
                transfer_cloud_id.clone(),
                bytes_total,
                upload_reporter.clone(),
            );
            match &upload_result {
                Ok(_) => break,
                Err(error) => {
                    if attempt_index + 1 == attempt_count
                        || !cloud_mcp_asset_transfer_error_is_retryable(error)
                    {
                        break;
                    }
                }
            }
        }
        let upload = upload_result?;
        drop(upload_reporter);
        if let Some(progress_thread) = progress_thread {
            let _ = progress_thread.join();
        }
        cloud_mcp_update_asset_library_from_response(
            "agent_asset_upload_http",
            Some("/v1/assets/upload"),
            &payload,
            &upload,
        );
        if direct_transfer {
            let mut complete_payload = cloud_mcp_asset_payload_base("agent_asset_upload_complete");
            if let Some(object) = complete_payload.as_object_mut() {
                object.insert("asset_id".to_string(), json!(asset_id));
                object.insert("assetId".to_string(), json!(asset_id));
                object.insert("transfer_id".to_string(), json!(transfer_id));
                object.insert("transferId".to_string(), json!(transfer_id));
                object.insert("cloud_id".to_string(), json!(transfer_cloud_id));
                object.insert("cloudId".to_string(), json!(transfer_cloud_id));
            }
            let response = cloud_mcp_proxy_post_json_endpoint(
                &base_url,
                "/v1/assets/complete-upload",
                &complete_payload.to_string(),
            )?;
            let parsed = serde_json::from_str::<Value>(&response)
                .unwrap_or_else(|_| json!({"raw_response": response}));
            let completed = parsed.get("data").cloned().unwrap_or(parsed);
            cloud_mcp_update_asset_library_from_response(
                "agent_asset_upload_direct_completed",
                Some("/v1/assets/complete-upload"),
                &complete_payload,
                &completed,
            );
            completed
        } else {
            upload
        }
    } else {
        prepare.clone()
    };
    Ok(json!({
        "kind": "asset_uploaded",
        "source": "managed_asset_library",
        "asset_id": asset_id,
        "assetId": asset_id,
        "asset": row,
        "prepare": prepare,
        "upload": upload,
        "upload_required": upload_required,
        "uploadRequired": upload_required,
    }))
}

pub(crate) fn cloud_mcp_forward_agent_delete_cloud_asset(
    _repo_path: Option<&str>,
    _workspace_id: Option<&str>,
    base_url_override: Option<&str>,
    input: &Value,
) -> Result<Value, String> {
    let asset_id = cloud_mcp_payload_text(input, &["asset_id", "assetId"])
        .ok_or_else(|| "delete_cloud_asset requires asset_id.".to_string())?;
    let mut payload = cloud_mcp_asset_payload_base("agent_asset_delete_cloud");
    if let Some(object) = payload.as_object_mut() {
        object.insert("asset_id".to_string(), json!(asset_id));
        object.insert("assetId".to_string(), json!(asset_id));
        if let Some(cloud_id) = cloud_mcp_payload_text(input, &["cloud_id", "cloudId"]) {
            object.insert("cloud_id".to_string(), json!(cloud_id));
            object.insert("cloudId".to_string(), json!(cloud_id));
        }
    }
    let base_url = base_url_override
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(|value| value.trim_end_matches('/').to_string())
        .unwrap_or_else(cloud_mcp_base_url);
    let response = cloud_mcp_proxy_post_json_endpoint(
        &base_url,
        "/v1/assets/delete-cloud",
        &payload.to_string(),
    )?;
    let parsed = serde_json::from_str::<Value>(&response)
        .unwrap_or_else(|_| json!({"raw_response": response}));
    let data = parsed.get("data").cloned().unwrap_or(parsed);
    cloud_mcp_update_asset_library_from_response(
        "agent_asset_delete_cloud",
        Some("/v1/assets/delete-cloud"),
        &payload,
        &data,
    );
    Ok(data)
}

pub(crate) fn cloud_mcp_forward_agent_delete_local_asset(
    repo_path: Option<&str>,
    workspace_id: Option<&str>,
    input: &Value,
) -> Result<Value, String> {
    let _ = (repo_path, workspace_id);
    let asset_id = cloud_mcp_payload_text(input, &["asset_id", "assetId"])
        .ok_or_else(|| "delete_local_asset requires asset_id.".to_string())?;
    let delete_file = cloud_mcp_payload_bool(input, &["delete_file", "deleteFile"], true);
    cloud_mcp_delete_local_asset_copy(&asset_id, delete_file)
}

pub(crate) fn cloud_mcp_forward_agent_download_asset(
    _repo_path: Option<&str>,
    _workspace_id: Option<&str>,
    base_url_override: Option<&str>,
    input: &Value,
) -> Result<Value, String> {
    let asset_id = cloud_mcp_payload_text(input, &["asset_id", "assetId", "id"])
        .ok_or_else(|| "download_asset requires asset_id.".to_string())?;
    let base_url = base_url_override
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(|value| value.trim_end_matches('/').to_string())
        .unwrap_or_else(cloud_mcp_base_url);
    let target_dir = cloud_mcp_payload_text(input, &["target_directory", "targetDirectory"])
        .map(PathBuf::from)
        .unwrap_or_else(|| {
            cloud_mcp_managed_asset_root()
                .unwrap_or_else(|_| PathBuf::from(".diffforge").join("assets"))
                .join("cloud")
                .join(&asset_id)
        });
    diffforge_reject_untracked_asset_path_for_tracking(&target_dir, "download a tracked asset")?;
    fs::create_dir_all(&target_dir)
        .map_err(|error| format!("Unable to create asset target directory: {error}"))?;
    let mut payload = cloud_mcp_asset_payload_base("agent_asset_download");
    if let Some(object) = payload.as_object_mut() {
        object.insert("asset_id".to_string(), json!(asset_id));
        object.insert("assetId".to_string(), json!(asset_id));
        if let Some(cloud_id) = cloud_mcp_payload_text(input, &["cloud_id", "cloudId"]) {
            object.insert("cloud_id".to_string(), json!(cloud_id));
            object.insert("cloudId".to_string(), json!(cloud_id));
        }
    }
    let response = cloud_mcp_proxy_post_json_endpoint(
        &base_url,
        "/v1/assets/prepare-download",
        &payload.to_string(),
    )?;
    let parsed = serde_json::from_str::<Value>(&response)
        .unwrap_or_else(|_| json!({"raw_response": response}));
    let prepare = parsed.get("data").cloned().unwrap_or(parsed);
    cloud_mcp_update_asset_library_from_response(
        "agent_asset_prepare_download",
        Some("/v1/assets/prepare-download"),
        &payload,
        &prepare,
    );
    let download_url = cloud_mcp_payload_text(&prepare, &["download_url", "downloadUrl"])
        .ok_or_else(|| "Cloud did not return an asset download URL.".to_string())?;
    let direct_transfer = cloud_mcp_asset_direct_presigned(&prepare);
    let download_path = if direct_transfer {
        cloud_mcp_payload_text(&prepare, &["download_path", "downloadPath"])
            .unwrap_or_else(|| download_url.clone())
    } else {
        cloud_mcp_payload_text(&prepare, &["download_path", "downloadPath"])
            .ok_or_else(|| "Cloud did not return an asset download path.".to_string())?
    };
    let http_target = if direct_transfer {
        CloudMcpAssetHttpTarget {
            url: download_url.clone(),
            route_token: None,
        }
    } else {
        cloud_mcp_asset_http_target_blocking(&base_url, &download_path)?
    };
    let mut attempts: Vec<(String, reqwest::header::HeaderMap)> = Vec::new();
    if direct_transfer {
        attempts.push((http_target.url.clone(), reqwest::header::HeaderMap::new()));
    } else {
        let token = cloud_mcp_process_authorization_bearer();
        attempts.push((
            http_target.url.clone(),
            cloud_mcp_asset_http_headers(token.as_deref(), http_target.route_token.as_deref())?,
        ));
    }
    let transfer_id = cloud_mcp_asset_prepare_transfer_id(&prepare, "download")?;
    let transfer_cloud_id = cloud_mcp_payload_text(&prepare, &["cloud_id", "cloudId"])
        .or_else(|| cloud_mcp_payload_text(input, &["cloud_id", "cloudId"]))
        .unwrap_or_else(|| "diffforge-ai-cloud".to_string());
    let expected_size =
        cloud_mcp_payload_i64(&prepare, &["size_bytes", "sizeBytes"]).unwrap_or_default();
    let expected_hash =
        cloud_mcp_payload_text(&prepare, &["expected_sha256", "expectedSha256", "sha256"])
            .unwrap_or_default();
    let asset = prepare.get("asset").cloned().unwrap_or_else(|| json!({}));
    let raw_name = cloud_mcp_payload_text(&asset, &["name", "filename"])
        .unwrap_or_else(|| format!("{asset_id}.asset"));
    let name = cloud_mcp_sanitize_asset_filename(&raw_name, &format!("{asset_id}.asset"));
    let target_path = cloud_mcp_available_asset_download_path(&target_dir, &name);
    let (progress_tx, mut progress_rx) = mpsc::unbounded_channel::<Value>();
    let progress_base_url = base_url.clone();
    let progress_thread = std::thread::spawn(move || {
        while let Some(progress) = progress_rx.blocking_recv() {
            let _ = cloud_mcp_proxy_post_json_endpoint(
                &progress_base_url,
                "/v1/assets/report-transfer-progress",
                &progress.to_string(),
            );
        }
    });
    let attempt_count = attempts.len();
    let mut download_result: Result<(), String> = Err("Asset download did not start.".to_string());
    for (attempt_index, (attempt_url, attempt_headers)) in attempts.into_iter().enumerate() {
        download_result = cloud_mcp_download_asset_streaming_blocking(
            attempt_url,
            attempt_headers,
            &target_path,
            &expected_hash,
            expected_size,
            asset_id.clone(),
            transfer_cloud_id.clone(),
            transfer_id.clone(),
            Some(progress_tx.clone()),
        );
        match &download_result {
            Ok(_) => break,
            Err(error) => {
                if attempt_index + 1 == attempt_count
                    || !cloud_mcp_asset_transfer_error_is_retryable(error)
                {
                    break;
                }
            }
        }
    }
    drop(progress_tx);
    let _ = progress_thread.join();
    let download = download_result?;
    let mut local_asset = asset;
    if let Some(object) = local_asset.as_object_mut() {
        object.insert(
            "local_path".to_string(),
            json!(target_path.display().to_string()),
        );
        object.insert(
            "localPath".to_string(),
            json!(target_path.display().to_string()),
        );
        object.insert("local_status".to_string(), json!("local_available"));
        object.insert("localStatus".to_string(), json!("local_available"));
    }
    cloud_mcp_asset_store_local_row(&local_asset)?;
    Ok(json!({
        "kind": "asset_downloaded",
        "source": "managed_asset_library",
        "asset_id": asset_id,
        "assetId": asset_id,
        "local_path": target_path.display().to_string(),
        "localPath": target_path.display().to_string(),
        "asset": local_asset,
        "prepare": prepare,
        "download": download,
    }))
}

fn cloud_mcp_asset_store_local_transfer_progress(
    asset_id: &str,
    transfer_id: &str,
    cloud_id: &str,
    direction: &str,
    status: &str,
    bytes_total: i64,
    bytes_done: i64,
    error: Option<&str>,
) -> Result<(), String> {
    cloud_mcp_record_asset_transfer_activity(
        asset_id,
        transfer_id,
        direction,
        status,
        bytes_total,
        bytes_done,
    );
    let conn = cloud_mcp_open_asset_library_conn()?;
    let row = cloud_mcp_asset_transfer_progress_row(
        asset_id,
        transfer_id,
        cloud_id,
        direction,
        status,
        bytes_total,
        bytes_done,
        error,
    );
    let update = cloud_mcp_update_asset_library_conn(
        &conn,
        "local_asset_transfer_progress",
        Some(cloud_mcp_base_url().as_str()),
        None,
        None,
        &json!({"transfers": [row.clone()]}),
    );
    if update.is_ok() {
        if let Some(sender) = CLOUD_MCP_ASSET_LOCAL_EVENT_SENDER.get() {
            let event_kind = if matches!(status, "failed" | "interrupted") {
                "asset_library_transfer_failed"
            } else {
                "asset_library_transfer_progress"
            };
            let _ = sender.send(json!({
                "kind": event_kind,
                "event_kind": event_kind,
                "eventKind": event_kind,
                "asset_id": asset_id,
                "assetId": asset_id,
                "transfer_id": transfer_id,
                "transferId": transfer_id,
                "payload": {
                    "kind": event_kind,
                    "transfers": [row.clone()],
                    "transfer": row.clone(),
                },
                "transfer": row,
            }));
        }
    }
    update
}

fn cloud_mcp_asset_transfer_progress_row(
    asset_id: &str,
    transfer_id: &str,
    cloud_id: &str,
    direction: &str,
    status: &str,
    bytes_total: i64,
    bytes_done: i64,
    error: Option<&str>,
) -> Value {
    let now = cloud_mcp_rfc3339_now();
    json!({
        "transfer_id": transfer_id,
        "transferId": transfer_id,
        "asset_id": asset_id,
        "assetId": asset_id,
        "cloud_id": cloud_id,
        "cloudId": cloud_id,
        "asset_scope": "account",
        "assetScope": "account",
        "library_scope": "account",
        "libraryScope": "account",
        "direction": direction,
        "status": status,
        "progress_source": "rust_client",
        "progressSource": "rust_client",
        "progress_basis": if direction == "upload" { "client_send" } else { "client_receive" },
        "progressBasis": if direction == "upload" { "client_send" } else { "client_receive" },
        "bytes_total": bytes_total,
        "bytesTotal": bytes_total,
        "bytes_done": bytes_done,
        "bytesDone": bytes_done,
        "error": error.unwrap_or_default(),
        "updated_at": now,
        "updatedAt": now,
    })
}

struct CloudMcpAssetTransferProgress {
    asset_id: String,
    transfer_id: String,
    cloud_id: String,
    direction: String,
    bytes_total: i64,
    bytes_done: i64,
    last_report_bytes: i64,
    last_report_at: Instant,
    reporter: Option<mpsc::UnboundedSender<Value>>,
}

impl CloudMcpAssetTransferProgress {
    fn new(
        asset_id: String,
        transfer_id: String,
        cloud_id: String,
        direction: &str,
        bytes_total: i64,
        reporter: Option<mpsc::UnboundedSender<Value>>,
    ) -> Self {
        Self {
            asset_id,
            transfer_id,
            cloud_id,
            direction: direction.to_string(),
            bytes_total,
            bytes_done: 0,
            last_report_bytes: 0,
            last_report_at: Instant::now(),
            reporter,
        }
    }

    fn report(&mut self, status: &str, bytes_done: i64, force: bool, error: Option<&str>) {
        let active_upload = self.direction == "upload"
            && status == "uploading"
            && self.bytes_total > 0
            && bytes_done >= self.bytes_total;
        self.bytes_done = if active_upload {
            self.bytes_total.saturating_sub(1)
        } else {
            bytes_done.max(0)
        };
        let report_step = cloud_mcp_asset_transfer_progress_step_bytes(self.bytes_total);
        let enough_bytes = self.bytes_done.saturating_sub(self.last_report_bytes) >= report_step;
        let enough_time = self.last_report_at.elapsed() >= Duration::from_millis(200);
        if !force && !enough_bytes && !enough_time {
            return;
        }
        let _ = cloud_mcp_asset_store_local_transfer_progress(
            &self.asset_id,
            &self.transfer_id,
            &self.cloud_id,
            &self.direction,
            status,
            self.bytes_total,
            self.bytes_done,
            error,
        );
        if let Some(reporter) = self.reporter.as_ref() {
            let _ = reporter.send(cloud_mcp_asset_transfer_progress_row(
                &self.asset_id,
                &self.transfer_id,
                &self.cloud_id,
                &self.direction,
                status,
                self.bytes_total,
                self.bytes_done,
                error,
            ));
        }
        self.last_report_bytes = self.bytes_done;
        self.last_report_at = Instant::now();
    }
}

static CLOUD_MCP_ASSET_TRANSFER_CANCEL_REQUESTS: OnceLock<std::sync::Mutex<HashSet<String>>> =
    OnceLock::new();

fn cloud_mcp_asset_cancel_requests() -> &'static std::sync::Mutex<HashSet<String>> {
    CLOUD_MCP_ASSET_TRANSFER_CANCEL_REQUESTS.get_or_init(|| std::sync::Mutex::new(HashSet::new()))
}

fn cloud_mcp_asset_cancel_key(value: &str) -> Option<String> {
    let key = value.trim().to_ascii_lowercase();
    (!key.is_empty()).then_some(key)
}

fn cloud_mcp_request_asset_transfer_cancel(keys: &[&str]) {
    if let Ok(mut requests) = cloud_mcp_asset_cancel_requests().lock() {
        for key in keys
            .iter()
            .filter_map(|value| cloud_mcp_asset_cancel_key(value))
        {
            requests.insert(key);
        }
    }
}

fn cloud_mcp_clear_asset_transfer_cancel(keys: &[&str]) {
    if let Ok(mut requests) = cloud_mcp_asset_cancel_requests().lock() {
        for key in keys
            .iter()
            .filter_map(|value| cloud_mcp_asset_cancel_key(value))
        {
            requests.remove(&key);
        }
    }
}

fn cloud_mcp_asset_transfer_cancelled(keys: &[&str]) -> bool {
    cloud_mcp_asset_cancel_requests()
        .lock()
        .map(|requests| {
            keys.iter()
                .filter_map(|value| cloud_mcp_asset_cancel_key(value))
                .any(|key| requests.contains(&key))
        })
        .unwrap_or(false)
}

/// Retry guard for the prepared-URL fallback after a routed transfer attempt:
/// transport failures and 5xx responses are route problems worth one retry,
/// while 4xx are real rejections and a user cancel must stay cancelled.
/// Matches the error strings produced by the blocking upload/download streamers.
fn cloud_mcp_asset_transfer_error_is_retryable(error: &str) -> bool {
    if error.contains("cancelled by user") {
        return false;
    }
    for prefix in ["Asset upload returned ", "Asset download returned "] {
        if let Some(rest) = error.strip_prefix(prefix) {
            let code = rest
                .split(':')
                .next()
                .and_then(|value| value.trim().parse::<u16>().ok())
                .unwrap_or(0);
            return (500..600).contains(&code);
        }
    }
    error.starts_with("Asset upload failed:") || error.starts_with("Asset download failed:")
}

fn cloud_mcp_asset_transfer_error_requires_reprepare(error: &str, direction: &str) -> bool {
    if error.contains("cancelled by user") {
        return false;
    }
    let lower = error.to_ascii_lowercase();
    let returned_404 = lower.contains(&format!("asset {direction} returned 404"));
    returned_404
        || lower.contains("asset transfer was not found")
        || lower.contains("asset_transfer_not_found")
        || lower.contains("unknown transfer")
        || lower.contains("prepared transfer")
}

fn cloud_mcp_delete_local_asset_transfer_rows(
    asset_id: &str,
    cloud_id: Option<&str>,
    direction: &str,
) {
    let asset_id = asset_id.trim();
    if asset_id.is_empty() {
        return;
    }
    let Ok(conn) = cloud_mcp_open_asset_library_conn() else {
        return;
    };
    let cloud_id = cloud_id.unwrap_or_default().trim();
    let direction = direction.trim();
    if cloud_id.is_empty() {
        let _ = conn.execute(
            "DELETE FROM account_asset_transfers
             WHERE asset_id=?1 AND direction=?2
               AND status IN ('queued', 'preparing', 'prepared', 'uploading', 'downloading',
                              'verifying', 'committing', 'warming_cache', 'failed', 'interrupted')",
            rusqlite::params![asset_id, direction],
        );
    } else {
        let _ = conn.execute(
            "DELETE FROM account_asset_transfers
             WHERE asset_id=?1 AND cloud_id=?2 AND direction=?3
               AND status IN ('queued', 'preparing', 'prepared', 'uploading', 'downloading',
                              'verifying', 'committing', 'warming_cache', 'failed', 'interrupted')",
            rusqlite::params![asset_id, cloud_id, direction],
        );
    }
}

struct CloudMcpAssetProgressReader {
    file: fs::File,
    progress: CloudMcpAssetTransferProgress,
}

impl Read for CloudMcpAssetProgressReader {
    fn read(&mut self, buf: &mut [u8]) -> std::io::Result<usize> {
        if cloud_mcp_asset_transfer_cancelled(&[
            &self.progress.asset_id,
            &self.progress.transfer_id,
        ]) {
            return Err(std::io::Error::new(
                std::io::ErrorKind::Interrupted,
                "Asset upload cancelled by user.",
            ));
        }
        let read = self.file.read(buf)?;
        if read > 0 {
            let done = self.progress.bytes_done.saturating_add(read as i64);
            self.progress.report("uploading", done, false, None);
        }
        Ok(read)
    }
}

fn cloud_mcp_upload_asset_streaming_blocking(
    url: String,
    headers: reqwest::header::HeaderMap,
    local_path: &Path,
    asset_id: String,
    transfer_id: String,
    cloud_id: String,
    bytes_total: i64,
    reporter: Option<mpsc::UnboundedSender<Value>>,
) -> Result<Value, String> {
    let fail_asset_id = asset_id.clone();
    let fail_transfer_id = transfer_id.clone();
    let fail_cloud_id = cloud_id.clone();
    let length = match fs::metadata(local_path) {
        Ok(metadata) => metadata.len(),
        Err(error) => {
            let message = format!(
                "Unable to inspect asset file {}: {error}",
                local_path.display()
            );
            let _ = cloud_mcp_asset_store_local_transfer_progress(
                &fail_asset_id,
                &fail_transfer_id,
                &fail_cloud_id,
                "upload",
                "failed",
                bytes_total,
                0,
                Some(&message),
            );
            return Err(message);
        }
    };
    if let Some(max_allowed_bytes) = cloud_mcp_asset_upload_exceeds_size_limit(length, bytes_total)
    {
        let error = format!(
            "Asset upload cancelled before transfer: file {} is {} bytes, exceeding declared size {} bytes plus {} bytes ({} bytes allowed).",
            local_path.display(),
            length,
            bytes_total,
            CLOUD_MCP_ASSET_UPLOAD_SIZE_SLACK_BYTES,
            max_allowed_bytes
        );
        let _ = cloud_mcp_asset_store_local_transfer_progress(
            &fail_asset_id,
            &fail_transfer_id,
            &fail_cloud_id,
            "upload",
            "failed",
            bytes_total,
            0,
            Some(&error),
        );
        return Err(error);
    }
    let file = match fs::File::open(local_path) {
        Ok(file) => file,
        Err(error) => {
            let message = format!(
                "Unable to open asset file {}: {error}",
                local_path.display()
            );
            let _ = cloud_mcp_asset_store_local_transfer_progress(
                &fail_asset_id,
                &fail_transfer_id,
                &fail_cloud_id,
                "upload",
                "failed",
                bytes_total,
                0,
                Some(&message),
            );
            return Err(message);
        }
    };
    let mut progress = CloudMcpAssetTransferProgress::new(
        asset_id,
        transfer_id,
        cloud_id,
        "upload",
        bytes_total,
        reporter,
    );
    progress.report("uploading", 0, true, None);
    let reader = CloudMcpAssetProgressReader { file, progress };
    let send_result = reqwest::blocking::Client::builder()
        .timeout(Duration::from_secs(CLOUD_MCP_ASSET_TRANSFER_TIMEOUT_SECS))
        .build()
        .map_err(|error| format!("Unable to create asset upload client: {error}"))?
        .put(url)
        .headers(headers)
        .body(reqwest::blocking::Body::sized(reader, length))
        .send();
    let response = match send_result {
        Ok(response) => response,
        Err(error) => {
            let cancelled =
                cloud_mcp_asset_transfer_cancelled(&[&fail_asset_id, &fail_transfer_id]);
            let (status, message) = if cancelled {
                ("interrupted", "Asset upload cancelled by user.".to_string())
            } else {
                ("failed", format!("Asset upload failed: {error}"))
            };
            let _ = cloud_mcp_asset_store_local_transfer_progress(
                &fail_asset_id,
                &fail_transfer_id,
                &fail_cloud_id,
                "upload",
                status,
                bytes_total,
                0,
                Some(&message),
            );
            return Err(message);
        }
    };
    let status = response.status();
    let response_text = response
        .text()
        .map_err(|error| format!("Unable to read asset upload response: {error}"))?;
    let upload_result = serde_json::from_str::<Value>(&response_text)
        .unwrap_or_else(|_| json!({"raw_response": response_text}));
    if !status.is_success() {
        let detail = upload_result
            .get("error")
            .and_then(|error| error.get("message"))
            .and_then(Value::as_str)
            .or_else(|| upload_result.get("error").and_then(Value::as_str))
            .or_else(|| upload_result.get("raw_response").and_then(Value::as_str))
            .map(|value| value.trim().chars().take(300).collect::<String>())
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| "upload failed".to_string());
        let message = format!("Asset upload returned {}: {}", status.as_u16(), detail);
        if !cloud_mcp_asset_transfer_error_requires_reprepare(&message, "upload") {
            let _ = cloud_mcp_asset_store_local_transfer_progress(
                &fail_asset_id,
                &fail_transfer_id,
                &fail_cloud_id,
                "upload",
                "failed",
                bytes_total,
                0,
                Some(&message),
            );
        }
        return Err(message);
    }
    let completed_bytes = bytes_total.max(i64::try_from(length).unwrap_or(i64::MAX));
    let _ = cloud_mcp_asset_store_local_transfer_progress(
        &fail_asset_id,
        &fail_transfer_id,
        &fail_cloud_id,
        "upload",
        "completed",
        completed_bytes,
        completed_bytes,
        None,
    );
    Ok(upload_result)
}

fn cloud_mcp_asset_upload_size_limit(bytes_total: i64) -> Option<u64> {
    let expected_bytes = u64::try_from(bytes_total).ok()?;
    Some(expected_bytes.saturating_add(CLOUD_MCP_ASSET_UPLOAD_SIZE_SLACK_BYTES))
}

fn cloud_mcp_asset_upload_exceeds_size_limit(actual_bytes: u64, bytes_total: i64) -> Option<u64> {
    let max_allowed_bytes = cloud_mcp_asset_upload_size_limit(bytes_total)?;
    (actual_bytes > max_allowed_bytes).then_some(max_allowed_bytes)
}

fn cloud_mcp_download_asset_streaming_blocking(
    url: String,
    headers: reqwest::header::HeaderMap,
    target_path: &Path,
    expected_hash: &str,
    expected_size: i64,
    asset_id: String,
    cloud_id: String,
    transfer_id: String,
    reporter: Option<mpsc::UnboundedSender<Value>>,
) -> Result<(), String> {
    let fail_asset_id = asset_id.clone();
    let fail_transfer_id = transfer_id.clone();
    let fail_cloud_id = cloud_id.clone();
    let failure_reporter = reporter.clone();
    let client = match reqwest::blocking::Client::builder()
        .timeout(Duration::from_secs(CLOUD_MCP_ASSET_TRANSFER_TIMEOUT_SECS))
        .build()
    {
        Ok(client) => client,
        Err(error) => {
            let message = format!("Unable to create asset download client: {error}");
            let _ = cloud_mcp_asset_store_local_transfer_progress(
                &fail_asset_id,
                &fail_transfer_id,
                &fail_cloud_id,
                "download",
                "failed",
                expected_size,
                0,
                Some(&message),
            );
            if let Some(reporter) = failure_reporter.as_ref() {
                let _ = reporter.send(cloud_mcp_asset_transfer_progress_row(
                    &fail_asset_id,
                    &fail_transfer_id,
                    &fail_cloud_id,
                    "download",
                    "failed",
                    expected_size,
                    0,
                    Some(&message),
                ));
            }
            return Err(message);
        }
    };
    let response = match client.get(url).headers(headers).send() {
        Ok(response) => response,
        Err(error) => {
            let message = format!("Asset download failed: {error}");
            let _ = cloud_mcp_asset_store_local_transfer_progress(
                &fail_asset_id,
                &fail_transfer_id,
                &fail_cloud_id,
                "download",
                "failed",
                expected_size,
                0,
                Some(&message),
            );
            if let Some(reporter) = failure_reporter.as_ref() {
                let _ = reporter.send(cloud_mcp_asset_transfer_progress_row(
                    &fail_asset_id,
                    &fail_transfer_id,
                    &fail_cloud_id,
                    "download",
                    "failed",
                    expected_size,
                    0,
                    Some(&message),
                ));
            }
            return Err(message);
        }
    };
    let status = response.status();
    if !status.is_success() {
        let response_text = response.text().unwrap_or_else(|error| {
            format!("Unable to read asset download error response: {error}")
        });
        let download_result = serde_json::from_str::<Value>(&response_text)
            .unwrap_or_else(|_| json!({"raw_response": response_text}));
        let detail = download_result
            .get("error")
            .and_then(|error| error.get("message"))
            .and_then(Value::as_str)
            .or_else(|| download_result.get("error").and_then(Value::as_str))
            .or_else(|| download_result.get("raw_response").and_then(Value::as_str))
            .map(|value| value.trim().chars().take(300).collect::<String>())
            .filter(|value| !value.is_empty())
            .unwrap_or_else(|| "download failed".to_string());
        let message = format!("Asset download returned {}: {}", status.as_u16(), detail);
        if !cloud_mcp_asset_transfer_error_requires_reprepare(&message, "download") {
            let _ = cloud_mcp_asset_store_local_transfer_progress(
                &fail_asset_id,
                &fail_transfer_id,
                &fail_cloud_id,
                "download",
                "failed",
                expected_size,
                0,
                Some(&message),
            );
            if let Some(reporter) = failure_reporter.as_ref() {
                let _ = reporter.send(cloud_mcp_asset_transfer_progress_row(
                    &fail_asset_id,
                    &fail_transfer_id,
                    &fail_cloud_id,
                    "download",
                    "failed",
                    expected_size,
                    0,
                    Some(&message),
                ));
            }
        }
        return Err(message);
    }
    cloud_mcp_write_download_response_to_file(
        response,
        target_path,
        expected_hash,
        expected_size,
        CloudMcpAssetTransferProgress::new(
            asset_id,
            transfer_id,
            cloud_id,
            "download",
            expected_size,
            reporter,
        ),
    )
}

fn cloud_mcp_write_download_response_to_file(
    mut response: reqwest::blocking::Response,
    target_path: &Path,
    expected_hash: &str,
    expected_size: i64,
    mut progress: CloudMcpAssetTransferProgress,
) -> Result<(), String> {
    if let Some(parent) = target_path.parent() {
        if let Err(error) = fs::create_dir_all(parent) {
            let message = format!("Unable to create asset download directory: {error}");
            progress.report("failed", progress.bytes_done, true, Some(&message));
            return Err(message);
        }
    }
    let staging = target_path.with_extension(format!("download-{}.tmp", uuid::Uuid::new_v4()));
    let mut file = match fs::File::create(&staging) {
        Ok(file) => file,
        Err(error) => {
            let message = format!("Unable to create downloaded asset: {error}");
            progress.report("failed", progress.bytes_done, true, Some(&message));
            return Err(message);
        }
    };
    let mut hasher = Sha256::new();
    let mut buffer = [0_u8; 256 * 1024];
    let mut bytes_done = 0_i64;
    progress.report("downloading", 0, true, None);
    loop {
        let cancel_keys = [progress.asset_id.clone(), progress.transfer_id.clone()];
        if cloud_mcp_asset_transfer_cancelled(&[&cancel_keys[0], &cancel_keys[1]]) {
            let _ = fs::remove_file(&staging);
            progress.report(
                "interrupted",
                bytes_done,
                true,
                Some("Asset download cancelled by user."),
            );
            return Err("Asset download cancelled by user.".to_string());
        }
        let read = match response.read(&mut buffer) {
            Ok(read) => read,
            Err(error) => {
                let _ = fs::remove_file(&staging);
                let message = format!("Unable to read asset download bytes: {error}");
                progress.report("failed", bytes_done, true, Some(&message));
                return Err(message);
            }
        };
        if read == 0 {
            break;
        }
        if let Err(error) = file.write_all(&buffer[..read]) {
            let _ = fs::remove_file(&staging);
            let message = format!("Unable to write downloaded asset: {error}");
            progress.report("failed", bytes_done, true, Some(&message));
            return Err(message);
        }
        hasher.update(&buffer[..read]);
        bytes_done = bytes_done.saturating_add(read as i64);
        progress.report("downloading", bytes_done, false, None);
    }
    if let Err(error) = file.flush() {
        let _ = fs::remove_file(&staging);
        let message = format!("Unable to flush downloaded asset: {error}");
        progress.report("failed", bytes_done, true, Some(&message));
        return Err(message);
    }
    if expected_size >= 0 && expected_size != bytes_done {
        let _ = fs::remove_file(&staging);
        let message =
            format!("Downloaded asset size mismatch: expected {expected_size}, got {bytes_done}");
        progress.report("failed", bytes_done, true, Some(&message));
        return Err(message);
    }
    if !expected_hash.is_empty() {
        let actual_hash = format!("{:x}", hasher.finalize());
        if actual_hash != expected_hash {
            let _ = fs::remove_file(&staging);
            let message = format!(
                "Downloaded asset hash mismatch: expected {expected_hash}, got {actual_hash}"
            );
            progress.report("failed", bytes_done, true, Some(&message));
            return Err(message);
        }
    }
    if let Err(error) = fs::rename(&staging, target_path) {
        let _ = fs::remove_file(&staging);
        let message = format!("Unable to finalize downloaded asset: {error}");
        progress.report("failed", bytes_done, true, Some(&message));
        return Err(message);
    }
    progress.report("completed", bytes_done, true, None);
    Ok(())
}

