pub(crate) fn cloud_mcp_forward_agent_wait_for_todos(
    repo_path: Option<&str>,
    db_path: Option<&Path>,
    workspace_id: Option<&str>,
    base_url_override: Option<&str>,
    agent_id: Option<&str>,
    session_id: Option<&str>,
    input: &Value,
) -> Result<Value, String> {
    const DEFAULT_TODO_WAIT_TIMEOUT_MS: i64 = 30_000;
    const MAX_TODO_WAIT_TIMEOUT_MS: i64 = 30_000;
    let timeout_ms = cloud_mcp_payload_i64(input, &["timeout_ms", "timeoutMs"])
        .unwrap_or(DEFAULT_TODO_WAIT_TIMEOUT_MS)
        .clamp(1_000, MAX_TODO_WAIT_TIMEOUT_MS) as u64;
    let until = cloud_mcp_payload_text(input, &["until"])
        .unwrap_or_else(|| "terminal".to_string())
        .trim()
        .to_ascii_lowercase()
        .replace(['-', ' '], "_");
    let started = std::time::Instant::now();
    let mut delay_ms = 250u64;
    loop {
        let status = cloud_mcp_forward_agent_get_todo_status(
            repo_path,
            db_path,
            workspace_id,
            base_url_override,
            agent_id,
            session_id,
            input,
        )?;
        let aggregate_status = status
            .get("aggregate")
            .and_then(|aggregate| aggregate.get("status"))
            .and_then(Value::as_str)
            .unwrap_or_default();
        let terminal = status
            .get("terminal")
            .and_then(Value::as_bool)
            .or_else(|| {
                status
                    .get("aggregate")
                    .and_then(|aggregate| aggregate.get("terminal"))
                    .and_then(Value::as_bool)
            })
            .unwrap_or(false);
        let satisfied = match until.as_str() {
            "accepted" => {
                matches!(
                    aggregate_status,
                    "accepted" | "running" | "attention_required" | "completed" | "partial_failed"
                ) || terminal
            }
            "running" => {
                matches!(
                    aggregate_status,
                    "running" | "attention_required" | "completed" | "partial_failed"
                ) || terminal
            }
            _ => terminal,
        };
        if satisfied {
            let mut response = status;
            if let Some(object) = response.as_object_mut() {
                object.insert("kind".to_string(), json!("todo_wait"));
                object.insert("wait_status".to_string(), json!("satisfied"));
                object.insert("waitStatus".to_string(), json!("satisfied"));
                object.insert(
                    "elapsed_ms".to_string(),
                    json!(started.elapsed().as_millis().min(u128::from(u64::MAX)) as u64),
                );
                object.insert(
                    "elapsedMs".to_string(),
                    json!(started.elapsed().as_millis().min(u128::from(u64::MAX)) as u64),
                );
            }
            return Ok(response);
        }
        if started.elapsed() >= std::time::Duration::from_millis(timeout_ms) {
            let mut response = status;
            if let Some(object) = response.as_object_mut() {
                object.insert("kind".to_string(), json!("todo_wait"));
                object.insert("wait_status".to_string(), json!("timed_out"));
                object.insert("waitStatus".to_string(), json!("timed_out"));
                object.insert("timeout_ms".to_string(), json!(timeout_ms));
                object.insert("timeoutMs".to_string(), json!(timeout_ms));
                object.insert(
                    "elapsed_ms".to_string(),
                    json!(started.elapsed().as_millis().min(u128::from(u64::MAX)) as u64),
                );
                object.insert(
                    "elapsedMs".to_string(),
                    json!(started.elapsed().as_millis().min(u128::from(u64::MAX)) as u64),
                );
            }
            return Ok(response);
        }
        std::thread::sleep(std::time::Duration::from_millis(delay_ms));
        delay_ms = (delay_ms.saturating_mul(2)).min(5_000);
    }
}

#[allow(clippy::too_many_arguments)]
fn cloud_mcp_forward_agent_todo_request(
    repo_path: Option<&str>,
    db_path: Option<&Path>,
    workspace_id: Option<&str>,
    base_url_override: Option<&str>,
    agent_id: Option<&str>,
    session_id: Option<&str>,
    input: &Value,
    endpoint: &str,
    tool_name: &str,
    source: &str,
) -> Result<Value, String> {
    let repo_path_text = repo_path
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string);
    let repo_id = repo_path_text
        .as_deref()
        .map(|value| format!("repo-{}", cloud_mcp_short_hash(value)));
    let base_url = base_url_override
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(|value| value.trim_end_matches('/').to_string())
        .unwrap_or_else(cloud_mcp_base_url);
    let identity = CloudMcpProxyIdentity {
        base_url: Some(base_url.clone()),
        repo_path: repo_path_text.as_ref().map(PathBuf::from),
        repo_id,
        workspace_id: workspace_id
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string),
        workspace_name: None,
        agent_id: agent_id
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string),
        session_id: session_id
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string),
        coordination_db_path: db_path.map(Path::to_path_buf),
        pane_id: None,
        terminal_instance_id: None,
        slot_key: None,
        agent_label: agent_id.and_then(cloud_mcp_short_agent_label),
        client_id: CLOUD_MCP_RUST_CLIENT_ID.to_string(),
    };
    let mut request = cloud_mcp_proxy_agent_base_payload(&identity, source);
    if let Some(object) = request.as_object_mut() {
        if let Some(input_object) = input.as_object() {
            for (key, value) in input_object {
                object.insert(key.clone(), value.clone());
            }
        }
        if let Some(repo_path) = repo_path_text.as_deref() {
            object.insert("repo_path".to_string(), json!(repo_path));
            object.insert("workspace_root".to_string(), json!(repo_path));
        }
        if let Some(workspace_id) = identity.workspace_id.as_deref() {
            object.insert("workspace_id".to_string(), json!(workspace_id));
            object.insert("workspaceId".to_string(), json!(workspace_id));
        }
    }
    identity.log(
        &format!("cloud_mcp.{tool_name}.start"),
        tool_name,
        json!({
            "activity": tool_name,
            "baseUrl": base_url,
            "endpoint": endpoint,
        }),
    );
    match cloud_mcp_proxy_post_json_endpoint(&base_url, endpoint, &request.to_string()) {
        Ok(response) => {
            let parsed = serde_json::from_str::<Value>(&response)
                .unwrap_or_else(|_| json!({"raw_response": response}));
            let data = parsed.get("data").cloned().unwrap_or(parsed);
            cloud_mcp_update_todo_mirror_file_from_response(
                tool_name,
                Some(&base_url),
                identity.repo_id.as_deref(),
                identity.workspace_id.as_deref(),
                &data,
            );
            identity.log(
                &format!("cloud_mcp.{tool_name}.done"),
                tool_name,
                json!({
                    "activity": tool_name,
                    "baseUrl": base_url,
                    "endpoint": endpoint,
                }),
            );
            Ok(data)
        }
        Err(error) => {
            identity.log(
                &format!("cloud_mcp.{tool_name}.error"),
                tool_name,
                json!({
                    "activity": tool_name,
                    "baseUrl": base_url,
                    "endpoint": endpoint,
                    "error": clean_terminal_telemetry_text(&error),
                }),
            );
            Err(error)
        }
    }
}

fn cloud_mcp_proxy_agent_base_payload(identity: &CloudMcpProxyIdentity, source: &str) -> Value {
    let mut payload = serde_json::Map::new();
    payload.insert("source".to_string(), json!(source));
    payload.insert("client_id".to_string(), json!(identity.client_id));
    payload.insert("ts_ms".to_string(), json!(cloud_mcp_now_ms()));
    if let Some(repo_id) = identity.repo_id.as_deref() {
        payload.insert("repo_id".to_string(), json!(repo_id));
        payload.insert("repoId".to_string(), json!(repo_id));
    }
    if let Some(repo_path) = identity.repo_path.as_ref() {
        let repo_path = repo_path.to_string_lossy().to_string();
        payload.insert("repo_path".to_string(), json!(repo_path.clone()));
        payload.insert("workspace_root".to_string(), json!(repo_path));
    }
    if let Some(workspace_id) = identity.workspace_id.as_deref() {
        payload.insert("workspace_id".to_string(), json!(workspace_id));
        payload.insert("workspaceId".to_string(), json!(workspace_id));
    }
    if let Some(agent_id) = identity.cloud_agent_id() {
        payload.insert("agent_id".to_string(), json!(agent_id.clone()));
        payload.insert("self_agent_id".to_string(), json!(agent_id.clone()));
        payload.insert("current_agent_id".to_string(), json!(agent_id));
    }
    if let Some(session_id) = identity.session_id.as_deref() {
        payload.insert("session_id".to_string(), json!(session_id));
    }
    Value::Object(payload)
}

fn cloud_mcp_proxy_normalize_todo_send_mode(mode: &str) -> Result<String, String> {
    let normalized = mode
        .trim()
        .to_ascii_lowercase()
        .replace(['-', ' ', '.'], "_");
    match normalized.as_str() {
        "" | "list" | "listed" | "listed_only" | "todo_list" => Ok("listed".to_string()),
        "queue" | "queued" | "dispatch" | "active_queue" | "run_if_online" => {
            Ok("queued".to_string())
        }
        _ => Err("todo send mode must be listed or queued.".to_string()),
    }
}

fn cloud_mcp_proxy_todo_targets_from_workspace_todos(
    workspace_todos: &Value,
    workspace_id: Option<&str>,
) -> Vec<Value> {
    let mut targets = Vec::<Value>::new();
    let mut seen = std::collections::HashSet::<String>::new();
    cloud_mcp_proxy_collect_todo_targets(
        workspace_todos
            .get("dispatchTargets")
            .or_else(|| workspace_todos.get("dispatch_targets")),
        workspace_id,
        &mut seen,
        &mut targets,
    );
    cloud_mcp_proxy_collect_todo_targets_by_workspace(
        workspace_todos
            .get("dispatchTargetsByWorkspace")
            .or_else(|| workspace_todos.get("dispatch_targets_by_workspace")),
        workspace_id,
        &mut seen,
        &mut targets,
    );
    targets
}

fn cloud_mcp_proxy_collect_todo_targets(
    collection: Option<&Value>,
    workspace_id: Option<&str>,
    seen: &mut std::collections::HashSet<String>,
    targets: &mut Vec<Value>,
) {
    let Some(collection) = collection else {
        return;
    };
    let items = collection
        .get("items")
        .and_then(Value::as_array)
        .or_else(|| collection.as_array());
    let Some(items) = items else {
        return;
    };
    for item in items {
        cloud_mcp_proxy_push_todo_target(item.clone(), workspace_id, seen, targets);
    }
}

fn cloud_mcp_proxy_collect_todo_targets_by_workspace(
    collection: Option<&Value>,
    workspace_id: Option<&str>,
    seen: &mut std::collections::HashSet<String>,
    targets: &mut Vec<Value>,
) {
    let Some(collection) = collection else {
        return;
    };
    let entries = collection
        .get("items")
        .and_then(Value::as_array)
        .or_else(|| collection.as_array());
    let Some(entries) = entries else {
        return;
    };
    for entry in entries {
        let observer_workspace_id = cloud_mcp_payload_text(
            entry,
            &[
                "workspace_id",
                "workspaceId",
                "observer_workspace_id",
                "observerWorkspaceId",
            ],
        )
        .unwrap_or_default();
        if workspace_id
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .is_some_and(|workspace_id| observer_workspace_id != workspace_id)
        {
            continue;
        }
        if let Some(items) = entry.get("items").and_then(Value::as_array) {
            for item in items {
                let mut item = item.clone();
                if let Some(object) = item.as_object_mut() {
                    object
                        .entry("observer_workspace_id".to_string())
                        .or_insert_with(|| json!(observer_workspace_id));
                }
                cloud_mcp_proxy_push_todo_target(item, workspace_id, seen, targets);
            }
        }
    }
}

fn cloud_mcp_proxy_push_todo_target(
    mut item: Value,
    workspace_id: Option<&str>,
    seen: &mut std::collections::HashSet<String>,
    targets: &mut Vec<Value>,
) {
    let target_device_id = cloud_mcp_payload_text(
        &item,
        &[
            "targetDeviceId",
            "target_device_id",
            "deviceId",
            "device_id",
        ],
    )
    .unwrap_or_default();
    let target_workspace_id = cloud_mcp_payload_text(
        &item,
        &[
            "targetWorkspaceId",
            "target_workspace_id",
            "workspaceId",
            "workspace_id",
        ],
    )
    .unwrap_or_default();
    if target_device_id.trim().is_empty() || target_workspace_id.trim().is_empty() {
        return;
    }
    if workspace_id
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .is_some_and(|workspace_id| {
            cloud_mcp_payload_text(
                &item,
                &[
                    "observer_workspace_id",
                    "observerWorkspaceId",
                    "workspace_id",
                    "workspaceId",
                ],
            )
            .as_deref()
                != Some(workspace_id)
        })
    {
        return;
    }
    let key = format!("{target_device_id}::{target_workspace_id}");
    if !seen.insert(key) {
        return;
    }
    if let Some(object) = item.as_object_mut() {
        object.insert("targetDeviceId".to_string(), json!(target_device_id));
        object.insert("target_device_id".to_string(), json!(target_device_id));
        object.insert("targetWorkspaceId".to_string(), json!(target_workspace_id));
        object.insert(
            "target_workspace_id".to_string(),
            json!(target_workspace_id),
        );
        object.insert("sameAccount".to_string(), json!(true));
        object.insert("same_account".to_string(), json!(true));
        object.insert("supportsListed".to_string(), json!(true));
        object.insert("supportsQueued".to_string(), json!(true));
    }
    targets.push(item);
}

fn cloud_mcp_task_cloud_sync_disabled() -> bool {
    true
}

fn cloud_mcp_task_cloud_sync_disabled_response(operation: &str, task_id: Option<&str>) -> Value {
    json!({
        "ok": true,
        "queued": false,
        "skipped": true,
        "reason": "cloud_task_sync_removed",
        "operation": operation,
        "task_id": task_id.unwrap_or_default(),
        "coordination_authority": "local",
        "cloud_sync_mode": "disabled",
    })
}

pub(crate) fn cloud_mcp_forward_agent_checkpoint(
    repo_path: Option<&str>,
    db_path: Option<&Path>,
    workspace_id: Option<&str>,
    agent_id: Option<&str>,
    session_id: Option<&str>,
    local_task_id: Option<&str>,
    worktree_id: Option<&str>,
    worktree_path: Option<&str>,
    summary: &str,
    terminal_todo_plan: Option<&Value>,
) -> Result<Value, String> {
    let active_task_id = local_task_id
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| {
            "checkpoint requires an active local task; read-only file inspection does not need checkpoints.".to_string()
        })?;
    if cloud_mcp_task_cloud_sync_disabled() {
        return Ok(cloud_mcp_task_cloud_sync_disabled_response(
            "checkpoint",
            Some(active_task_id),
        ));
    }
    let repo_path_text = repo_path
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string);
    let worktree_path_text = worktree_path
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string);
    let scan_path_text = worktree_path_text
        .as_ref()
        .or(repo_path_text.as_ref())
        .cloned();
    let repo_id = repo_path_text
        .as_deref()
        .or(scan_path_text.as_deref())
        .map(|value| format!("repo-{}", cloud_mcp_short_hash(value)));
    let base_url = cloud_mcp_base_url();
    let identity = CloudMcpProxyIdentity {
        base_url: Some(base_url.clone()),
        repo_path: scan_path_text.as_ref().map(PathBuf::from),
        repo_id,
        workspace_id: workspace_id
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string),
        workspace_name: None,
        agent_id: agent_id
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string),
        session_id: session_id
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string),
        coordination_db_path: db_path.map(Path::to_path_buf),
        pane_id: None,
        terminal_instance_id: None,
        slot_key: None,
        agent_label: agent_id.and_then(cloud_mcp_short_agent_label),
        client_id: CLOUD_MCP_RUST_CLIENT_ID.to_string(),
    };
    let event_kind = "checkpoint_recorded";
    let mut metadata = serde_json::Map::new();
    metadata.insert(
        "reported_by".to_string(),
        json!("coordination-kernel.checkpoint"),
    );
    metadata.insert(
        "local_coordination_task_id".to_string(),
        json!(active_task_id),
    );
    metadata.insert("coordination_task_id".to_string(), json!(active_task_id));
    if let Some(worktree_id) = worktree_id {
        metadata.insert("worktree_id".to_string(), json!(worktree_id));
    }
    if let Some(worktree_path) = worktree_path {
        metadata.insert("worktree_path".to_string(), json!(worktree_path));
    }
    if let Some(plan) = terminal_todo_plan.filter(|value| !value.is_null()) {
        metadata.insert("terminal_todo_plan".to_string(), plan.clone());
    }

    let mut arguments = serde_json::Map::new();
    arguments.insert(
        "source".to_string(),
        json!("rust-diffforge-agent-checkpoint"),
    );
    arguments.insert("client_id".to_string(), json!(identity.client_id.clone()));
    arguments.insert("subtask".to_string(), json!(summary));
    arguments.insert("brief".to_string(), json!(summary));
    arguments.insert("summary".to_string(), json!(summary));
    arguments.insert("agent_status".to_string(), json!("active"));
    arguments.insert("metadata".to_string(), Value::Object(metadata));
    if let Some(plan) = terminal_todo_plan.filter(|value| !value.is_null()) {
        arguments.insert("terminal_todo_plan".to_string(), plan.clone());
    }
    arguments.insert("task_id".to_string(), json!(active_task_id));
    arguments.insert("run_id".to_string(), json!(active_task_id));
    if let Some(repo_id) = identity.repo_id.as_deref() {
        arguments.insert("repo_id".to_string(), json!(repo_id));
    }
    if let Some(repo_path) = repo_path_text.as_deref().or(scan_path_text.as_deref()) {
        arguments.insert("repo_path".to_string(), json!(repo_path));
        arguments.insert("workspace_root".to_string(), json!(repo_path));
    }
    if let Some(workspace_id) = identity.workspace_id.as_deref() {
        arguments.insert("workspace_id".to_string(), json!(workspace_id));
    }
    if let Some(agent_id) = identity.cloud_agent_id() {
        arguments.insert("agent_id".to_string(), json!(agent_id.clone()));
        arguments.insert("self_agent_id".to_string(), json!(agent_id.clone()));
        arguments.insert("current_agent_id".to_string(), json!(agent_id));
    }
    if let Some(session_id) = identity.session_id.as_deref() {
        arguments.insert("session_id".to_string(), json!(session_id));
    }
    cloud_mcp_proxy_insert_local_file_scope(&mut arguments, &identity, event_kind);

    let payload = Value::Object(arguments);
    identity.log(
        "cloud_mcp.agent_checkpoint.queued",
        event_kind,
        json!({
            "activity": "agent checkpoint cloud sync skipped",
            "baseUrl": base_url,
            "summary": clean_terminal_telemetry_text(summary),
        }),
    );
    cloud_mcp_queue_event_background(&base_url, event_kind, &payload, "agent_checkpoint")
}

pub(crate) fn cloud_mcp_forward_terminal_todo_plan_update(
    repo_path: Option<&str>,
    db_path: Option<&Path>,
    workspace_id: Option<&str>,
    agent_id: Option<&str>,
    session_id: Option<&str>,
    local_task_id: Option<&str>,
    worktree_id: Option<&str>,
    worktree_path: Option<&str>,
    update_reason: &str,
    terminal_todo_plan: &Value,
) -> Result<Value, String> {
    if terminal_todo_plan.is_null() {
        return Err("terminal todo plan sync requires a compact terminal_todo_plan.".to_string());
    }
    let active_task_id = local_task_id
        .map(str::trim)
        .filter(|value| !value.is_empty());
    if cloud_mcp_task_cloud_sync_disabled() {
        return Ok(cloud_mcp_task_cloud_sync_disabled_response(
            "terminal_todo_plan_update",
            active_task_id,
        ));
    }
    let active_task_id = active_task_id
        .ok_or_else(|| "terminal todo plan sync requires an active task_id.".to_string())?;
    let repo_path_text = repo_path
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string);
    let worktree_path_text = worktree_path
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string);
    let scan_path_text = worktree_path_text
        .as_ref()
        .or(repo_path_text.as_ref())
        .cloned();
    let repo_id = repo_path_text
        .as_deref()
        .or(scan_path_text.as_deref())
        .map(|value| format!("repo-{}", cloud_mcp_short_hash(value)));
    let base_url = cloud_mcp_base_url();
    let identity = CloudMcpProxyIdentity {
        base_url: Some(base_url.clone()),
        repo_path: scan_path_text.as_ref().map(PathBuf::from),
        repo_id,
        workspace_id: workspace_id
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string),
        workspace_name: None,
        agent_id: agent_id
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string),
        session_id: session_id
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string),
        coordination_db_path: db_path.map(Path::to_path_buf),
        pane_id: None,
        terminal_instance_id: None,
        slot_key: None,
        agent_label: agent_id.and_then(cloud_mcp_short_agent_label),
        client_id: CLOUD_MCP_RUST_CLIENT_ID.to_string(),
    };
    let event_kind = "terminal_todo_plan_updated";
    let mut metadata = serde_json::Map::new();
    metadata.insert(
        "reported_by".to_string(),
        json!("coordination-kernel.terminal_todo_plan"),
    );
    metadata.insert(
        "local_coordination_task_id".to_string(),
        json!(active_task_id),
    );
    metadata.insert("coordination_task_id".to_string(), json!(active_task_id));
    metadata.insert("terminal_todo_plan".to_string(), terminal_todo_plan.clone());
    if let Some(worktree_id) = worktree_id {
        metadata.insert("worktree_id".to_string(), json!(worktree_id));
    }
    if let Some(worktree_path) = worktree_path {
        metadata.insert("worktree_path".to_string(), json!(worktree_path));
    }

    let mut arguments = serde_json::Map::new();
    arguments.insert(
        "source".to_string(),
        json!("rust-diffforge-terminal-todo-plan"),
    );
    arguments.insert("client_id".to_string(), json!(identity.client_id.clone()));
    arguments.insert("task_id".to_string(), json!(active_task_id));
    arguments.insert("run_id".to_string(), json!(active_task_id));
    arguments.insert("summary".to_string(), json!("Terminal todo plan updated."));
    arguments.insert("update_reason".to_string(), json!(update_reason));
    arguments.insert("metadata".to_string(), Value::Object(metadata));
    arguments.insert("terminal_todo_plan".to_string(), terminal_todo_plan.clone());
    if let Some(repo_id) = identity.repo_id.as_deref() {
        arguments.insert("repo_id".to_string(), json!(repo_id));
    }
    if let Some(repo_path) = repo_path_text.as_deref().or(scan_path_text.as_deref()) {
        arguments.insert("repo_path".to_string(), json!(repo_path));
        arguments.insert("workspace_root".to_string(), json!(repo_path));
    }
    if let Some(workspace_id) = identity.workspace_id.as_deref() {
        arguments.insert("workspace_id".to_string(), json!(workspace_id));
    }
    if let Some(agent_id) = identity.cloud_agent_id() {
        arguments.insert("agent_id".to_string(), json!(agent_id.clone()));
        arguments.insert("self_agent_id".to_string(), json!(agent_id.clone()));
        arguments.insert("current_agent_id".to_string(), json!(agent_id));
    }
    if let Some(session_id) = identity.session_id.as_deref() {
        arguments.insert("session_id".to_string(), json!(session_id));
    }
    cloud_mcp_proxy_insert_local_file_scope(&mut arguments, &identity, event_kind);

    let payload = Value::Object(arguments);
    identity.log(
        "cloud_mcp.terminal_todo_plan.queued",
        event_kind,
        json!({
            "activity": "terminal todo plan cloud sync skipped",
            "baseUrl": base_url,
            "taskId": active_task_id,
            "reason": clean_terminal_telemetry_text(update_reason),
        }),
    );
    cloud_mcp_queue_event_background(&base_url, event_kind, &payload, "terminal_todo_plan_update")
}

fn cloud_mcp_normalized_relative_path(value: &str) -> Option<String> {
    let path = value
        .replace('\\', "/")
        .trim()
        .trim_matches('/')
        .to_string();
    if path.is_empty()
        || path == ".git"
        || path == ".agents"
        || path.starts_with(".git/")
        || path.starts_with(".agents/")
        || path.starts_with("../")
        || path.contains("/../")
    {
        return None;
    }
    Some(path)
}

fn cloud_mcp_lease_path_from_resource_key(resource_key: &str) -> Option<String> {
    let trimmed = resource_key.trim();
    if trimmed.is_empty()
        || trimmed.starts_with("glob:")
        || trimmed.starts_with("route:")
        || trimmed.starts_with("db:")
    {
        return None;
    }
    let path = trimmed.strip_prefix("file:").unwrap_or(trimmed);
    cloud_mcp_normalized_relative_path(path)
}

pub(crate) fn cloud_mcp_forward_agent_acquire_lease(
    _repo_path: Option<&str>,
    _db_path: Option<&Path>,
    _workspace_id: Option<&str>,
    _agent_id: Option<&str>,
    _session_id: Option<&str>,
    task_id: Option<&str>,
    _worktree_id: Option<&str>,
    _worktree_path: Option<&str>,
    resource_key: &str,
    mode: &str,
    reason: Option<&str>,
    acquire_result: &Value,
) -> Result<Value, String> {
    if acquire_result["ok"].as_bool() != Some(true) {
        return Ok(json!({"skipped": true, "reason": "lease_not_acquired"}));
    }
    let active_task_id = task_id
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| {
            "acquire_lease Cloud sync requires the task_id returned by start_task.".to_string()
        })?;
    let Some(path) = cloud_mcp_lease_path_from_resource_key(resource_key) else {
        return Ok(json!({"skipped": true, "reason": "non_file_resource"}));
    };
    // Leases are locally authoritative: the coordination kernel records them.
    // Lease acquisition no longer emits a cloud event.
    log_cloud_sync_event(
        "lease.local_only",
        json!({
            "resource_key": resource_key,
            "path": path,
            "mode": mode,
            "task_id": active_task_id,
            "reason": reason.unwrap_or_default(),
        }),
    );
    Ok(json!({
        "skipped": true,
        "reason": "lease_sync_is_local",
        "task_id": active_task_id,
    }))
}

pub(crate) fn cloud_mcp_forward_agent_submit_patch(
    repo_path: Option<&str>,
    db_path: Option<&Path>,
    workspace_id: Option<&str>,
    agent_id: Option<&str>,
    session_id: Option<&str>,
    task_id: Option<&str>,
    worktree_id: Option<&str>,
    worktree_path: Option<&str>,
    summary: Option<&str>,
    local_task_status: Option<&str>,
    submit_result: &Value,
    terminal_todo_plan: Option<&Value>,
) -> Result<Value, String> {
    let active_task_id = task_id
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| {
            "submit_patch Cloud sync requires the task_id returned by start_task.".to_string()
        })?;
    if cloud_mcp_task_cloud_sync_disabled() {
        return Ok(cloud_mcp_task_cloud_sync_disabled_response(
            "submit_patch",
            Some(active_task_id),
        ));
    }
    let repo_path_text = repo_path
        .or(worktree_path)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string);
    let repo_id = repo_path_text
        .as_deref()
        .map(|value| format!("repo-{}", cloud_mcp_short_hash(value)));
    let base_url = cloud_mcp_base_url();
    let identity = CloudMcpProxyIdentity {
        base_url: Some(base_url.clone()),
        repo_path: repo_path_text.as_ref().map(PathBuf::from),
        repo_id,
        workspace_id: workspace_id
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string),
        workspace_name: None,
        agent_id: agent_id
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string),
        session_id: session_id
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string),
        coordination_db_path: db_path.map(Path::to_path_buf),
        pane_id: None,
        terminal_instance_id: None,
        slot_key: None,
        agent_label: agent_id.and_then(cloud_mcp_short_agent_label),
        client_id: CLOUD_MCP_RUST_CLIENT_ID.to_string(),
    };
    let data = submit_result.get("data").unwrap_or(&Value::Null);
    let ok = submit_result["ok"].as_bool() == Some(true);
    let validation_status = data["validation_status"].as_str().unwrap_or_default();
    let auto_merge_status = data["auto_merge"]["status"].as_str().unwrap_or_default();
    let task_status = local_task_status
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
        .unwrap_or_else(|| {
            if data["noop"].as_bool() == Some(true) {
                "skipped".to_string()
            } else if ok && auto_merge_status == "applied" {
                "merged".to_string()
            } else if ok && validation_status == "passed" {
                "review".to_string()
            } else {
                "review".to_string()
            }
        });
    let changed_files = data
        .get("changed_files")
        .cloned()
        .unwrap_or_else(|| json!([]));
    let changed_file_paths = cloud_mcp_submit_patch_changed_file_paths(submit_result);
    let mut metadata = serde_json::Map::new();
    metadata.insert(
        "reported_by".to_string(),
        json!("coordination-kernel.submit_patch"),
    );
    metadata.insert("submit_result".to_string(), submit_result.clone());
    metadata.insert("validation_status".to_string(), json!(validation_status));
    metadata.insert("auto_merge_status".to_string(), json!(auto_merge_status));
    metadata.insert("cloud_task_id".to_string(), json!(active_task_id));
    metadata.insert("coordination_task_id".to_string(), json!(active_task_id));
    metadata.insert(
        "local_coordination_task_id".to_string(),
        json!(active_task_id),
    );
    if let Some(patch_id) = data["patch_id"].as_str() {
        metadata.insert("local_patch_id".to_string(), json!(patch_id));
    }
    if let Some(diff_artifact_id) = data["diff_artifact_id"].as_str() {
        metadata.insert(
            "local_diff_artifact_id".to_string(),
            json!(diff_artifact_id),
        );
    }
    if let Some(worktree_id) = worktree_id {
        metadata.insert("worktree_id".to_string(), json!(worktree_id));
    }
    if let Some(worktree_path) = worktree_path {
        metadata.insert("worktree_path".to_string(), json!(worktree_path));
    }
    if let Some(plan) = terminal_todo_plan.filter(|value| !value.is_null()) {
        metadata.insert("terminal_todo_plan".to_string(), plan.clone());
    }

    let mut arguments = serde_json::Map::new();
    let summary_text = summary.unwrap_or("Patch submitted through the local coordination kernel.");
    arguments.insert(
        "source".to_string(),
        json!("rust-diffforge-agent-submit-patch"),
    );
    arguments.insert("client_id".to_string(), json!(identity.client_id.clone()));
    arguments.insert("status".to_string(), json!(task_status.clone()));
    arguments.insert("task_status".to_string(), json!(task_status.clone()));
    arguments.insert("summary".to_string(), json!(summary_text));
    arguments.insert("brief".to_string(), json!(summary_text));
    arguments.insert("changed_files".to_string(), changed_files);
    arguments.insert("metadata".to_string(), Value::Object(metadata));
    arguments.insert("task_id".to_string(), json!(active_task_id));
    arguments.insert("run_id".to_string(), json!(active_task_id));
    if let Some(plan) = terminal_todo_plan.filter(|value| !value.is_null()) {
        arguments.insert("terminal_todo_plan".to_string(), plan.clone());
    }
    if let Some(repo_id) = identity.repo_id.as_deref() {
        arguments.insert("repo_id".to_string(), json!(repo_id));
    }
    if let Some(repo_path) = identity.repo_path.as_ref() {
        let repo_path = repo_path.to_string_lossy().to_string();
        arguments.insert("repo_path".to_string(), json!(repo_path.clone()));
        arguments.insert("workspace_root".to_string(), json!(repo_path));
    }
    if let Some(workspace_id) = identity.workspace_id.as_deref() {
        arguments.insert("workspace_id".to_string(), json!(workspace_id));
    }
    if let Some(agent_id) = identity.cloud_agent_id() {
        arguments.insert("agent_id".to_string(), json!(agent_id.clone()));
        arguments.insert("self_agent_id".to_string(), json!(agent_id.clone()));
        arguments.insert("current_agent_id".to_string(), json!(agent_id));
    }
    if let Some(session_id) = identity.session_id.as_deref() {
        arguments.insert("session_id".to_string(), json!(session_id));
    }

    let event_kind = "submit_patch";
    let payload = Value::Object(arguments);
    identity.log(
        "cloud_mcp.agent_submit_patch.queued",
        "submit_patch",
        json!({
            "activity": "agent submit_patch cloud sync skipped",
            "baseUrl": base_url,
            "taskStatus": task_status,
            "taskId": active_task_id,
        }),
    );
    let mut queued =
        cloud_mcp_queue_event_background(&base_url, event_kind, &payload, "agent_submit_patch")?;
    let isolated_prune = if ok {
        json!({"ok": false, "skipped": true, "reason": "patch_accepted"})
    } else {
        cloud_mcp_forward_isolated_work_pruned(
            &base_url,
            &identity,
            active_task_id,
            worktree_id,
            worktree_path,
            &changed_file_paths,
            "submit_patch_rejected",
            submit_result,
        )
        .unwrap_or_else(|error| json!({"ok": false, "error": error}))
    };
    if let Some(object) = queued.as_object_mut() {
        object.insert("isolated_prune".to_string(), isolated_prune);
    }
    Ok(queued)
}

